  @override
  void initState() {
    super.initState();
    // Use sport-appropriate category order immediately so hockey shows 1. Offense, 2. Defense, 3. Goalie... from first paint
    _categoryOrder = List.from(categoryOrder);
    _initializePreferences();
    // Rebuild when magic bar focus changes to toggle verb bolding and switch to list mode
    _magicBarFocusNode.addListener(() {
      print(
        'DEBUG: Magic bar focus changed. Has focus: ${_magicBarFocusNode.hasFocus}',
      );
      setState(() {
        // Switch to list mode when magic bar is focused for easier player selection
        if (_magicBarFocusNode.hasFocus) {
          _homePlayerView = 'list';
          _awayPlayerView = 'list';
        }
      });
    });
    _homeSearchController.addListener(() {
      setState(() {
        _homeSearchText = _homeSearchController.text;
      });
    });
    _awaySearchController.addListener(() {
      setState(() {
        _awaySearchText = _awaySearchController.text;
      });
    });
    _unifiedSearchController.addListener(() {
      setState(() {
        _unifiedSearchText = _unifiedSearchController.text;
      });
    });
    _keyboardFireCaptionNotifier.value = captionController.text;
    captionController.addListener(_syncKeyboardFireCaptionNotifier);
    _initializeSampleData();
    if (widget.personalityOverride != null) {
      personalityController.text = widget.personalityOverride!;
    }
    _loadFtpProfiles();
  }

  void _onCaptionFieldVisibilityRevision() {
    if (!mounted) return;
    setState(() {
      _showHeadlineField = _preferencesService.captionFieldHeadlineVisibleSync;
      _showKeywordsField = _preferencesService.captionFieldKeywordsVisibleSync;
      _showPersonalityField =
          _preferencesService.captionFieldPersonalityVisibleSync;
    });
  }

  void _syncKeyboardFireCaptionNotifier() {
    _keyboardFireCaptionNotifier.value = captionController.text;
  }

  @override
  void dispose() {
    captionController.removeListener(_syncKeyboardFireCaptionNotifier);
    // Store current metadata before disposing
    _storeCurrentMetadata();

    // Save preferences before disposing
    _savePreferences();

    _homeSearchController.dispose();
    _awaySearchController.dispose();
    _unifiedSearchController.dispose();
    _magicBarController.dispose();
    _magicBarFocusNode.dispose();
    _verbNumbersFocusNode.dispose();
    _numberBufferTimer?.cancel();
    if (_captionFieldVisibilityListenerAttached) {
      _preferencesService.captionFieldVisibilityRevision
          .removeListener(_onCaptionFieldVisibilityRevision);
    }
    headlineController.dispose();
    keywordsController.dispose();
    super.dispose();
  }

  Future<void> _initializePreferences() async {
    _preferencesService = await PreferencesService.getInstance();
    await _loadPreferences();
  }

  Future<void> _loadPreferences() async {
    // Use sport from widget parameter, or load from preferences
    _currentSport = widget.sport?.toLowerCase() ??
        await _preferencesService.getCurrentSport();

    // Load category order for current sport (or use default for sport if not saved)
    final savedCategoryOrder =
        await _preferencesService.getCategoryOrder(sport: _currentSport);
    _categoryOrder =
        savedCategoryOrder.isNotEmpty ? savedCategoryOrder : categoryOrder;

    // Load favorite verbs for current sport
    _favoriteVerbs =
        await _preferencesService.getFavoriteVerbs(sport: _currentSport);

    // Load custom verb wordings for current sport
    _customVerbWordings =
        await _preferencesService.getCustomVerbWordings(sport: _currentSport);

    // Load verb overrides (from verb editor)
    _verbOverrides =
        await _preferencesService.getVerbOverrides(sport: _currentSport);

    // Load deleted verbs (hidden from list)
    _deletedVerbs =
        await _preferencesService.getDeletedVerbs(sport: _currentSport);

    // Load firebar position
    _placeFirebarOnRight = await _preferencesService.getPlaceFirebarOnRight();

    _applyVerbKeywordsEnabled =
        await _preferencesService.getApplyVerbKeywords();
    _applyPlayerNamesToKeywordsEnabled =
        await _preferencesService.getApplyPlayerNamesToKeywords();

    // Load last saved metadata
    _lastSavedMetadata = await _preferencesService.getLastSavedMetadata();

    _showHeadlineField = _preferencesService.captionFieldHeadlineVisibleSync;
    _showKeywordsField = _preferencesService.captionFieldKeywordsVisibleSync;
    _showPersonalityField =
        _preferencesService.captionFieldPersonalityVisibleSync;
    if (!_captionFieldVisibilityListenerAttached) {
      _preferencesService.captionFieldVisibilityRevision
          .addListener(_onCaptionFieldVisibilityRevision);
      _captionFieldVisibilityListenerAttached = true;
    }

    // Load FTP profiles
    _ftpProfiles = await _preferencesService.getFtpProfiles();
    _currentFtpProfile = await _preferencesService.getCurrentFtpProfile();

    if (mounted) {
      setState(() {
        _preferencesLoaded = true;
      });
    }
  }

  Future<void> _savePreferences() async {
    await _preferencesService.saveCategoryOrder(_categoryOrder,
        sport: _currentSport);
    await _preferencesService.saveFavoriteVerbs(_favoriteVerbs,
        sport: _currentSport);
    await _preferencesService.savePlaceFirebarOnRight(_placeFirebarOnRight);
    await _preferencesService.saveApplyVerbKeywords(_applyVerbKeywordsEnabled);
    await _preferencesService
        .saveApplyPlayerNamesToKeywords(_applyPlayerNamesToKeywordsEnabled);
    await _preferencesService.saveLastSavedMetadata(_lastSavedMetadata);
    await _preferencesService.saveFtpProfiles(_ftpProfiles);
    await _preferencesService.saveCurrentFtpProfile(_currentFtpProfile);
    await _preferencesService.saveCurrentSport(_currentSport);
  }

  void _initializeSampleData() {
    // Initialize with teams from app bar, or null if not provided
    selectedHomeTeam = widget.homeTeam;
    selectedAwayTeam = widget.awayTeam;

    // Don't initialize controllers with default values - only load from EXIF data

    // Load rosters from MLB API only if both teams are provided
    if (selectedHomeTeam != null && selectedAwayTeam != null) {
      _loadTeamRosters();
    }
  }

  Future<void> _fetchAndSetVenueForGame() async {
    if (selectedHomeTeam == null || selectedAwayTeam == null) return;

    // Get the photo date from metadata
    DateTime gameDate = DateTime.now();
    if (widget.metadata != null) {
      final dateTimeOriginal = widget.metadata!['DateTimeOriginal']?.toString();
      final createDate = widget.metadata!['CreateDate']?.toString();
      final modifyDate = widget.metadata!['ModifyDate']?.toString();

      // Try to parse the date from EXIF data
      final dateString = dateTimeOriginal ?? createDate ?? modifyDate;
      if (dateString != null && dateString.isNotEmpty) {
        try {
          // Parse EXIF date format (YYYY:MM:DD HH:MM:SS)
          final parts = dateString.split(' ');
          if (parts.isNotEmpty) {
            final datePart = parts[0];
            final dateComponents = datePart.split(':');
            if (dateComponents.length >= 3) {
              final year = int.parse(dateComponents[0]);
              final month = int.parse(dateComponents[1]);
              final day = int.parse(dateComponents[2]);
              gameDate = DateTime(year, month, day);
              print(
                'DEBUG: Venue fetch - Parsed game date: ${gameDate.toIso8601String().split('T')[0]}',
              );
            }
          }
        } catch (e) {
          print('Error parsing photo date: $e');
          // Fallback to current date
        }
      } else {
        print(
          'DEBUG: Venue fetch - No date string found in metadata, using current date',
        );
      }
    } else {}

    try {
      final venue = await _apiManager.fetchVenueForGame(
        selectedHomeTeam!,
        selectedAwayTeam!,
        gameDate,
      );
      // Removed auto-population of stadium and city/state from venue data
      // Only load values from EXIF metadata, not from API
    } catch (e) {
      print('Error fetching venue for game: $e');
    }
  }
  // Removed _setCityFromStadium function - no auto-population of city/state

  Future<void> _loadTeamRosters() async {
    if (selectedHomeTeam == null || selectedAwayTeam == null) return;

    // Check if we have preloaded roster data
    if (widget.preloadedHomeRoster != null &&
        widget.preloadedAwayRoster != null) {
      setState(() {
        _homeRoster = widget.preloadedHomeRoster!;
        _awayRoster = widget.preloadedAwayRoster!;
        _isLoadingRosters = false;

        // Clear any existing selections since rosters have changed
        selectedHomePlayers.clear();
        selectedAwayPlayers.clear();
        _firstTeamSelected = null; // Reset first team selection
        _firstPlayerSelected = null; // Reset first player selection
        print(
          'DEBUG: Using preloaded rosters: ${_homeRoster.length} home players, ${_awayRoster.length} away players',
        );
      });

      // Fetch venue information for the specific game and update stadium field
      if (selectedHomeTeam != null &&
          selectedAwayTeam != null &&
          stadiumController.text.isEmpty) {
        _fetchAndSetVenueForGame();
      }

      return; // Skip API calls since we have preloaded data
    }

    setState(() {
      _isLoadingRosters = true;
    });

    try {
      // Load both team rosters and team info in parallel
      final futures = await Future.wait([
        _apiManager.fetchTeamRoster(selectedHomeTeam!),
        _apiManager.fetchTeamRoster(selectedAwayTeam!),
        _apiManager.fetchTeams().then(
              (teams) => teams.firstWhere(
                (team) => team.name == selectedHomeTeam,
                orElse: () => throw Exception('Team not found'),
              ),
            ),
        _apiManager.fetchTeams().then(
              (teams) => teams.firstWhere(
                (team) => team.name == selectedAwayTeam,
                orElse: () => throw Exception('Team not found'),
              ),
            ),
      ]);

      setState(() {
        _homeRoster = futures[0] as List<Player>;
        _awayRoster = futures[1] as List<Player>;
        final homeTeamInfo = futures[2] as TeamInfo?;
        final awayTeamInfo = futures[3] as TeamInfo?;

        // Set stadium names from API (will be fetched separately for balldontlie)
        homeTeamStadium = null; // Will be fetched separately
        awayTeamStadium = null; // Will be fetched separately

        // Fetch venue information for the specific game and update stadium field
        if (selectedHomeTeam != null &&
            selectedAwayTeam != null &&
            stadiumController.text.isEmpty) {
          _fetchAndSetVenueForGame();
        }

        _isLoadingRosters = false;

        // Clear any existing selections since rosters have changed
        selectedHomePlayers.clear();
        selectedAwayPlayers.clear();
        _firstTeamSelected = null; // Reset first team selection
        _firstPlayerSelected = null; // Reset first player selection
      });

      print(
        'Successfully loaded rosters: ${_homeRoster.length} home players, ${_awayRoster.length} away players',
      );
      print('Home team stadium: $homeTeamStadium');
      print('Away team stadium: $awayTeamStadium');
    } catch (e) {
      print('Error loading team rosters: $e');
      setState(() {
        _isLoadingRosters = false;
      });

      // Show error message to user
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Failed to load team rosters: ${e.toString()}'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

  @override
  void didUpdateWidget(CaptionFieldsWidget oldWidget) {
    super.didUpdateWidget(oldWidget);

    // Check if sport has changed and reload preferences
    if (oldWidget.sport != widget.sport) {
      // Show correct category order immediately for the new sport (e.g. hockey -> 1. Offense, 2. Defense, 3. Goalie...)
      _categoryOrder = List.from(categoryOrder);
      _loadPreferences();
    }

    if (widget.personalityOverride != null &&
        widget.personalityOverride != oldWidget.personalityOverride) {
      personalityController.text = widget.personalityOverride!;
    }
    if (widget.metadata != oldWidget.metadata) {
      // Only auto-store if the save handler hasn't already done it explicitly.
      // After an explicit save, _skipNextAutoStore is true to prevent
      // didUpdateWidget from overwriting the correct (verb-inclusive) caption
      // with a stale captionController.text.
      if (!_skipNextAutoStore) {
        _storeCurrentMetadata();
      }
      _skipNextAutoStore = false;

      // New image or first metadata: full reset. Same image (e.g. IPTC save): players only
      // so inning/verb stay; player chips clear for the next frame.
      final bool imageIdentityChanged =
          widget.currentImagePath != oldWidget.currentImagePath ||
              widget.currentIndex != oldWidget.currentIndex;
      final bool firstMetadataBind =
          oldWidget.metadata == null && widget.metadata != null;
      if (imageIdentityChanged || firstMetadataBind) {
        resetCaptionSelections();
      } else {
        _resetPlayerSelectionsForSameImageMetadata();
      }
      _loadMetadata();
    }

    // Check if teams have changed
    if (oldWidget.homeTeam != widget.homeTeam ||
        oldWidget.awayTeam != widget.awayTeam) {
      setState(() {
        selectedHomeTeam = widget.homeTeam;
        selectedAwayTeam = widget.awayTeam;

        // Clear existing selections and rosters
        selectedHomePlayers.clear();
        selectedAwayPlayers.clear();
        _firstTeamSelected = null; // Reset first team selection
        _firstPlayerSelected = null; // Reset first player selection

        _homeRoster.clear();
        _awayRoster.clear();
      });

      // Load new rosters if both teams are selected
      if (selectedHomeTeam != null && selectedAwayTeam != null) {
        _loadTeamRosters();
      }
    }
  }

  void _loadMetadata() {
    // If a reset has been performed, do not load metadata again.
    if (_hasBeenReset) return;

    if (widget.metadata == null) return;
    final meta = widget.metadata!;

    // Load Caption: Prefer Photo Mechanic's IPTC Description, then fallback to other fields
    final dynamic iptcDescription =
        meta['IPTC:Description'] ?? meta['Description'];
    final dynamic captionAbstract =
        meta['Caption-Abstract'] ?? meta['IPTC:Caption-Abstract'];
    final dynamic imageDescription = meta['ImageDescription'];
    final dynamic xmpDescription = meta['XMP:Description'];
    final extractedCaption =
        (iptcDescription is String ? iptcDescription : '') ??
            (captionAbstract is String ? captionAbstract : '') ??
            (imageDescription is String ? imageDescription : '') ??
            (xmpDescription is String ? xmpDescription : '') ??
            '';

    // Load Personality: Read from XMP-getty:Personality
    final dynamic extractedPersonality =
        meta['XMP-getty:Personality'] ?? meta['Personality'];
    final personInImageText = (extractedPersonality is List)
        ? extractedPersonality.join(';')
        : (extractedPersonality is String ? extractedPersonality : '');

    // Load location fields from metadata - prefer Photo Mechanic's IPTC fields
    final dynamic subLocation =
        meta['IPTC:SubLocation'] ?? meta['SubLocation'] ?? meta['Sub-location'];
    final dynamic city = meta['IPTC:City'] ?? meta['City'];
    final dynamic province = meta['IPTC:ProvinceState'] ??
        meta['ProvinceState'] ??
        meta['Province-State'];
    final extractedStadium = subLocation is String ? subLocation : '';
    final extractedCity = city is String ? city : '';
    final extractedProvince = province is String ? province : '';

    final dynamic headlineRaw = meta['IPTC:Headline'] ?? meta['Headline'];
    final String extractedHeadline = headlineRaw is String
        ? headlineRaw
        : (headlineRaw != null ? headlineRaw.toString() : '');

    final dynamic keywordsRaw = meta['IPTC:Keywords'] ?? meta['Keywords'];
    final String extractedKeywords = _dedupeKeywordsForDisplay(keywordsRaw);

    // Creator field is now handled by metadata widget only

    setState(() {
      _originalCaptionFromMetadata = extractedCaption;
      _originalPersonalityFromMetadata = personInImageText;
      captionController.text = extractedCaption;
      personalityController.text = personInImageText;
      headlineController.text = extractedHeadline;
      keywordsController.text = extractedKeywords;

      // Only set personality from metadata if the user hasn't manually reset.
      if (!_hasBeenReset) {
        personalityController.text = personInImageText;
      }

      // Load location fields from metadata
      stadiumController.text = extractedStadium;
      cityController.text = extractedCity;
      provinceController.text = extractedProvince;

      // Creator field is now handled by metadata widget only
    });

    // Apply any pending pinned verb synchronously after metadata loads.
    // This runs after the setState above, so we are the last write to the
    // caption for this navigation event — no post-frame timing races.
    if (_pendingPinnedVerbCategory != null && _pendingPinnedVerbIndex != null) {
      final cat = _pendingPinnedVerbCategory!;
      final idx = _pendingPinnedVerbIndex!;
      _pendingPinnedVerbCategory = null;
      _pendingPinnedVerbIndex = null;
      // Force _selectedVerb to null first so selectVerb doesn't toggle it off.
      _selectedVerb = null;
      _selectedActionVerb = null;
      final hasExistingCaption = extractedCaption.trim().isNotEmpty;
      // If the photo already has a caption, highlight the pinned verb in the
      // UI but do NOT regenerate the caption — preserve what's in the file.
      // If there's no caption yet, generate one from the pinned verb as normal.
      selectVerbByCategoryAndIndexFromKeyboardFire(cat, idx,
          suppressCaptionUpdate: hasExistingCaption);
      if (!hasExistingCaption) {
        updateCaptionFromKeyboardFire();
      }
    }
  }

  /// After metadata refresh for the **same** image (e.g. save), clear player picks
  /// and search state only. Keeps inning, verb, RBI/base options, etc.
  void _resetPlayerSelectionsForSameImageMetadata() {
    setState(() {
      selectedHomePlayers.clear();
      selectedAwayPlayers.clear();
      _firstPlayerSelected = null;
      _firstTeamSelected = null;

      _filteredPlayers.clear();
      _noPlayersFound = false;
      _isPlayerSearchMode = true;
      _magicInputMatchingPlayers.clear();
      _magicInputActionText = '';
      _waitingForHomeVisitorChoice = false;

      _homeSearchController.clear();
      _awaySearchController.clear();
      _unifiedSearchController.clear();
      _homeSearchText = '';
      _awaySearchText = '';
      _unifiedSearchText = '';
    });
  }

  // Reset all caption building selections when navigating to a new image
  void resetCaptionSelections() {
    setState(() {
      // Clear player selections
      selectedHomePlayers.clear();
      selectedAwayPlayers.clear();
      _firstPlayerSelected = null;
      _firstTeamSelected = null;

      // Clear verb selections
      _selectedVerb = null;
      _selectedActionVerb = null;
      _stickyVerb = null;
      _selectedHittingAction = null;

      // Clear celebration settings
      _isCelebratingWithTeammates = false;

      // Clear other selections
      _rbiCount = null;
      _selectedRbiInning = null;

      // Clear search states
      _filteredPlayers.clear();
      _noPlayersFound = false;
      _isPlayerSearchMode = true; // Reset to player search mode
      _showCustomTextInningSelector = false; // Hide inning selector
      _magicInputMatchingPlayers.clear();
      _magicInputActionText = '';
      _waitingForHomeVisitorChoice = false;

      // Clear custom text fields
      customCelebrationController.clear();
      customDejectionController.clear();
      // Magic bar removed: no-op placeholder

      // Clear search bars
      _homeSearchController.clear();
      _awaySearchController.clear();
      _unifiedSearchController.clear();
      _unifiedSearchController.clear();
      _homeSearchText = '';
      _awaySearchText = '';
      _unifiedSearchText = '';

      // Reset hasBeenReset flag to allow metadata loading
      _hasBeenReset = false;
    });
  }

  // Public method to reset caption selections (can be called from parent)
  void resetSelections() {
    resetCaptionSelections();
  }

  // Process all valid codes when spacebar is pressed
  void _processAllValidCodesOnSpacebar(String value) {
    // Find all valid codes that end with a space and process them
    final codeMatches = RegExp(
      r'([hv]\d{1,3}|[hv]{2}\d{1,3}|[hv][tv]|[hv]|[ag]|[ah]|[av]|[i]\d{1,3}|\d{1,2}[i]|[d][i]\d{1,3}|[d]\d{1,2}[i]) ',
    ).allMatches(value);

    for (final match in codeMatches) {
      final code = match.group(0)!.trim();
      _processCodeOnSpacebar(value, match, code);
    }
  }

  // Process code when spacebar is pressed
  void _processCodeOnSpacebar(String value, RegExpMatch match, String code) {
    // Process the code every time spacebar is pressed (allow repetition)

    // Process different types of codes
    final lowerCode = code.toLowerCase();

    // Player codes: h27, v15, hh27, vv15
    if (RegExp(r'^[hv]\d{1,3}$').hasMatch(lowerCode) ||
        RegExp(r'^[hv]{2}\d{1,3}$').hasMatch(lowerCode)) {
      _processPlayerCode(value, match, code);
    }
    // Team codes: ht, vt, h, v
    else if (RegExp(r'^[hv][tv]?$').hasMatch(lowerCode)) {
      _processTeamCode(value, match, code);
    }
    // Against codes: ag, ah, av
    else if (lowerCode == 'ag') {
      _processAgainstCode(value, match, code);
    } else if (lowerCode == 'ah') {
      _processAgainstHomeCode(value, match, code);
    } else if (lowerCode == 'av') {
      _processAgainstVisitingCode(value, match, code);
    }
    // Inning code: i3, i15, 1i, 27i
    else if (RegExp(r'^i\d{1,3}$').hasMatch(lowerCode) ||
        RegExp(r'^\d{1,2}i$').hasMatch(lowerCode)) {
      _processInningCode(value, match, code);
    }
    // During inning code: di3, di15, d1i, d27i
    else if (RegExp(r'^di\d{1,3}$').hasMatch(lowerCode) ||
        RegExp(r'^d\d{1,2}i$').hasMatch(lowerCode)) {
      _processDuringInningCode(value, match, code);
    }
  }

  // Process player code (h27, v15, hh27, vv15, etc.)
  void _processPlayerCode(String value, RegExpMatch match, String code) {
    final lowerCode = code.toLowerCase();

    // Determine if it's a double-letter code (hh or vv)
    final isDouble = lowerCode.startsWith('hh') || lowerCode.startsWith('vv');

    // Extract the team prefix and number
    String prefix;
    String number;
    if (isDouble) {
      prefix = lowerCode.substring(0, 2); // hh or vv
      number = lowerCode.substring(2); // everything after hh or vv
    } else {
      prefix = lowerCode.substring(0, 1); // h or v
      number = lowerCode.substring(1); // everything after h or v
    }

    final isHome = prefix.startsWith('h');
    final roster = isHome ? _homeRoster : _awayRoster;

    // Find the player
    Player? found;
    for (final p in roster) {
      if (p.jerseyNumber == number) {
        found = p;
        break;
      }
    }

    if (found != null) {
      // Build replacement text
      String replacement = found.displayName;

      // Add team name only for single-letter codes (h2, v15), not double-letter codes (hh2, vv15)
      if (!isDouble) {
        final teamName = isHome ? selectedHomeTeam : selectedAwayTeam;
        if (teamName != null && teamName.isNotEmpty) {
          replacement = '$replacement of the $teamName';
        }
      }

      replacement = '$replacement ';
      _replaceCodeInText(value, match, replacement);

      // Update personality field with clean full name (no number), de-duplicated
      final current = personalityController.text.trim();
      final parts = current.isEmpty
          ? <String>[]
          : current
              .split(';')
              .map((s) => s.trim())
              .where((s) => s.isNotEmpty)
              .toList();
      if (!parts.contains(found.fullName)) {
        parts.add(found.fullName);
        personalityController.text = parts.join(';');
      }

      // Visually select the player in the picker
      _selectPlayerChipByNumber(
        isHomeTeam: isHome,
        jerseyNumber: number,
        isProgressive: true,
      );
    }
  }

  // Process team code (ht, vt, h, v)
  void _processTeamCode(String value, RegExpMatch match, String code) {
    final lowerCode = code.toLowerCase();
    String replacement = '';

    // For single "h" or "v", check that it's not part of another word
    if (lowerCode == 'h' || lowerCode == 'v') {
      // Get the character before the match (if any)
      final charBeforeMatch = match.start > 0 ? value[match.start - 1] : ' ';

      // Only replace if preceded by space or at beginning of text
      if (charBeforeMatch != ' ' && match.start != 0) {
        // Don't replace - it's part of another word
        return;
      }
    }

    if (lowerCode == 'ht') {
      replacement = selectedHomeTeam ?? 'Home Team';
    } else if (lowerCode == 'vt') {
      replacement = selectedAwayTeam ?? 'Visiting Team';
    } else if (lowerCode == 'h') {
      replacement = selectedHomeTeam ?? 'Home Team';
    } else if (lowerCode == 'v') {
      replacement = selectedAwayTeam ?? 'Away Team';
    }

    if (replacement.isNotEmpty) {
      replacement = '$replacement ';
      _replaceCodeInText(value, match, replacement);
    }
  }

  // Process against code (ag)
  void _processAgainstCode(String value, RegExpMatch match, String code) {
    String oppositeTeam = '';

    // Scan the caption text to see which team is already mentioned
    final captionText = captionController.text;
    final homeTeamMentioned =
        selectedHomeTeam != null && captionText.contains(selectedHomeTeam!);
    final awayTeamMentioned =
        selectedAwayTeam != null && captionText.contains(selectedAwayTeam!);

    if (homeTeamMentioned && !awayTeamMentioned) {
      oppositeTeam = selectedAwayTeam ?? '';
    } else if (awayTeamMentioned && !homeTeamMentioned) {
      oppositeTeam = selectedHomeTeam ?? '';
    } else if (selectedHomePlayers.isNotEmpty && selectedAwayPlayers.isEmpty) {
      oppositeTeam = selectedAwayTeam ?? '';
    } else if (selectedAwayPlayers.isNotEmpty && selectedHomePlayers.isEmpty) {
      oppositeTeam = selectedHomeTeam ?? '';
    } else {
      oppositeTeam = selectedAwayTeam ?? '';
    }

    final replacement = oppositeTeam.isNotEmpty
        ? 'against the $oppositeTeam '
        : 'against the opposing team ';
    _replaceCodeInText(value, match, replacement);
  }

  // Process against home team code (ah)
  void _processAgainstHomeCode(String value, RegExpMatch match, String code) {
    final replacement = selectedHomeTeam != null && selectedHomeTeam!.isNotEmpty
        ? 'against the $selectedHomeTeam '
        : 'against the home team ';
    _replaceCodeInText(value, match, replacement);
  }

  // Process against visiting team code (av)
  void _processAgainstVisitingCode(
    String value,
    RegExpMatch match,
    String code,
  ) {
    final replacement = selectedAwayTeam != null && selectedAwayTeam!.isNotEmpty
        ? 'against the $selectedAwayTeam '
        : 'against the visiting team ';
    _replaceCodeInText(value, match, replacement);
  }

  // Process inning code (i3, i15, 1i, 27i, etc.)
  void _processInningCode(String value, RegExpMatch match, String code) {
    String number;

    // Handle both formats: i3 and 3i
    if (code.startsWith('i')) {
      number = code.substring(1); // i3 -> 3
    } else {
      number = code.substring(0, code.length - 1); // 3i -> 3
    }

    final inningNum = int.tryParse(number) ?? 0;

    if (inningNum == 0 || inningNum > 27) return;

    final ord = _getOrdinalSuffix(inningNum);
    final replacement = '$ord inning ';
    _replaceCodeInText(value, match, replacement);
  }

  // Process during inning code (di3, di15, d1i, d27i, etc.)
  void _processDuringInningCode(String value, RegExpMatch match, String code) {
    String number;

    // Handle both formats: di3 and d3i
    if (code.toLowerCase().startsWith('di')) {
      number = code.substring(2); // di3 -> 3
    } else {
      number = code.substring(1, code.length - 1); // d3i -> 3
    }

    final inningNum = int.tryParse(number) ?? 0;

    if (inningNum == 0 || inningNum > 27) return;

    final ord = _getOrdinalSuffix(inningNum);
    final replacement = 'during the $ord inning ';
    _replaceCodeInText(value, match, replacement);
  }

  // Helper method to replace code in text
  void _replaceCodeInText(String value, RegExpMatch match, String replacement) {
    final beforeCode = value.substring(0, match.start);
    final afterCode = value.substring(match.end);
    final newText = beforeCode + replacement + afterCode;

    _isProcessingCaptionShortcut = true;
    captionController.text = newText;

    // Position cursor after the replacement
    final cursorPos = beforeCode.length + replacement.length;
    captionController.selection = TextSelection.collapsed(offset: cursorPos);

    // Clear highlighting after code is processed
    captionController.highlightedRanges = [];
    captionController.invalidRanges = [];
    _highlightedRanges.clear();

    _isProcessingCaptionShortcut = false;
  }

  // Process player token found in caption box
  void _processCaptionPlayerToken(
    String value,
    RegExpMatch match,
    Player player,
    bool isHome,
  ) {
    _isProcessingCaptionShortcut = true;

    // Replace the token with the player name
    final beforeToken = value.substring(0, match.start);
    final afterToken = value.substring(match.end);
    final replacement = '${player.displayName ?? 'Unknown Player'} ';

    final newText = beforeToken + replacement + afterToken;
    captionController.text = newText;

    // Use the caption box's built-in highlighting system for a lighter color
    final replacementStart = beforeToken.length;
    final replacementEnd =
        replacementStart + replacement.length - 1; // Exclude the trailing space

    setState(() {
      _highlightedRanges.clear();
      _highlightedRanges.add(
        TextRange(start: replacementStart, end: replacementEnd),
      );
    });

    // Position cursor at the end of the highlighted text
    captionController.selection = TextSelection.fromPosition(
      TextPosition(offset: replacementEnd + 1), // +1 to go after the space
    );

    // Visually select the player in the picker
    _selectPlayerChipByNumber(
      isHomeTeam: isHome,
      jerseyNumber: player.jerseyNumber ?? '',
      isProgressive: true,
    );

    // Update personality field
    final current = personalityController.text.trim();
    final parts = current.isEmpty
        ? <String>[]
        : current
            .split(';')
            .map((s) => s.trim())
            .where((s) => s.isNotEmpty)
            .toList();
    if (!parts.contains(player.fullName ?? '')) {
      parts.add(player.fullName ?? '');
      personalityController.text = parts.join(';');
    }

    _isProcessingCaptionShortcut = false;
  }

  // Handle hNN / vNN shorthand typed in the caption box
  void _onCaptionChanged(String value) {
    if (_isProcessingCaptionShortcut) return;

    // Check for spacebar-triggered code replacement
    if (value.isNotEmpty) {
      // Get cursor position to find if a space was just typed
      final selection = captionController.selection;
      if (selection.isValid) {
        final cursorPos = selection.baseOffset;

        // Check if there's a space just before the cursor position
        if (cursorPos > 0 && value[cursorPos - 1] == ' ') {
          print(
            'DEBUG: Space detected at cursor position $cursorPos in: "$value"',
          );

          // Look for codes that end just before the cursor (just before the space)
          final codeMatches = RegExp(
            r'([hv]\d{1,3}|[hv]{2}\d{1,3}|[hv][tv]|[hv]|[ag]|[ah]|[av]|[i]\d{1,3}) ',
          ).allMatches(value);

          // Find the code that ends right at the cursor position
          RegExpMatch? bestMatch;

          for (final match in codeMatches) {
            print(
              'DEBUG: Code at ${match.start}-${match.end} (${match.group(0)?.trim()}), ends at: ${match.end}, cursor at: $cursorPos',
            );
            if (match.end == cursorPos) {
              // Code ends exactly where cursor is
              bestMatch = match;
              break;
            }
          }

          if (bestMatch != null) {
            final code = bestMatch.group(0)!.trim();

            // Process the code (this will handle all types: player, team, inning, against)
            _processCodeOnSpacebar(value, bestMatch, code);
            return;
          }
        }
      }
    }

    // Only proceed with expansion if the last character typed was a space
    if (value.isEmpty || value.codeUnitAt(value.length - 1) != 32) {
      // Don't highlight tokens until spacebar is pressed - this prevents false matches
      // like "h" in "eighth" being detected as a player code
      captionController.highlightedRanges = [];
      captionController.invalidRanges = [];
      return;
    }

    // Process all valid codes when spacebar is pressed
    _processAllValidCodesOnSpacebar(value);
  }

  // Remove a player's full name from the personality field text (semicolon-separated, de-duplicated)
  void _removePlayerFromPersonality(String playerName) {
    final current = personalityController.text.trim();
    final parts = current.isEmpty
        ? <String>[]
        : current
            .split(';')
            .map((s) => s.trim())
            .where((s) => s.isNotEmpty)
            .toList();
    parts.removeWhere((p) => p == playerName);
    personalityController.text = parts.join(';');
  }

  // Highlight potential tokens as they are typed, including reversed numeric forms
  void _highlightPotentialTokens(String value) {
    if (value.isEmpty) {
      captionController.highlightedRanges = [];
      captionController.invalidRanges = [];
      setState(() {});
      return;
    }

    final List<TextRange> validRanges = [];
    final List<TextRange> invalidRanges = [];

    // Forward tokens: h, hh, v, vv, i, di, ht, vt, ag, ah, av + optional number (for player/inning)
    final forward = RegExp(
      r'(?:^|\s)((?:[hH]{1,2})|(?:[vV]{1,2})|[iI]|[dD][iI]|[hH][tT]|[vV][tT]|(?<!a)[aA][gG](?!a)|[aA][hH]|[aA][vV])(\d{0,3})',
    );
    for (final m in forward.allMatches(value)) {
      final prefix = m.group(1)!.toLowerCase();
      final number = m.group(2) ?? '';

      bool isPlayerToken =
          (prefix == 'h' || prefix == 'hh' || prefix == 'v' || prefix == 'vv');
      bool isValid = false;
      if (prefix == 'i') {
        // For inning codes (i), only highlight if they are complete (end with space or at end of text)
        final isComplete = m.end == value.length ||
            (m.end < value.length && value[m.end] == ' ');
        isValid = isComplete &&
            number.isNotEmpty &&
            int.tryParse(number) != null &&
            int.parse(number) >= 1 &&
            int.parse(number) <= 27; // inning requires a number 1-27
      } else if (prefix == 'di') {
        // For during inning codes (di), only highlight if they are complete (end with space or at end of text)
        final isComplete = m.end == value.length ||
            (m.end < value.length && value[m.end] == ' ');
        isValid = isComplete &&
            number.isNotEmpty &&
            int.tryParse(number) != null &&
            int.parse(number) >= 1 &&
            int.parse(number) <= 27; // during inning requires a number 1-27
      } else if (prefix == 'ht' ||
          prefix == 'vt' ||
          prefix == 'ag' ||
          prefix == 'ah' ||
          prefix == 'av') {
        isValid = true; // no number required
      } else if (isPlayerToken && number.isNotEmpty) {
        final isHome = prefix.startsWith('h');
        final roster = isHome ? _homeRoster : _awayRoster;
        isValid = roster.any((p) => p.jerseyNumber == number);
      }

      final range = TextRange(start: m.start, end: m.end);
      if (isValid) {
        validRanges.add(range);
      } else if (isPlayerToken && number.isNotEmpty) {
        invalidRanges.add(range);
      }
    }

    // Reversed numeric tokens at the end: NN(h|hh|v|vv|i) - limit to 2 digits for inning
    final reverse = RegExp(r'(?:^|\s)(\d{1,2})(([hH]{1,2})|([vV]{1,2})|[iI])');
    for (final m in reverse.allMatches(value)) {
      final number = m.group(1) ?? '';
      final suffix = (m.group(2) ?? '').toLowerCase();

      bool isPlayerToken =
          (suffix == 'h' || suffix == 'hh' || suffix == 'v' || suffix == 'vv');
      bool isValid = false;
      if (suffix == 'i') {
        // For inning codes (i), only highlight if they are complete (end with space or at end of text)
        final isComplete = m.end == value.length ||
            (m.end < value.length && value[m.end] == ' ');
        isValid = isComplete &&
            number.isNotEmpty &&
            int.tryParse(number) != null &&
            int.parse(number) >= 1 &&
            int.parse(number) <= 27; // inning requires a number 1-27
      } else if (isPlayerToken && number.isNotEmpty) {
        final isHome = suffix.startsWith('h');
        final roster = isHome ? _homeRoster : _awayRoster;
        isValid = roster.any((p) => p.jerseyNumber == number);
      }

      final range = TextRange(start: m.start, end: m.end);
      if (isValid) {
        validRanges.add(range);
      } else if (isPlayerToken) {
        invalidRanges.add(range);
      }
    }

    // During inning reversed pattern: d(NN)i - limit to 2 digits for inning
    final duringReverse = RegExp(r'(?:^|\s)[dD](\d{1,2})[iI]');
    for (final m in duringReverse.allMatches(value)) {
      final number = m.group(1) ?? '';

      // For during inning codes (d1i), only highlight if they are complete (end with space or at end of text)
      final isComplete = m.end == value.length ||
          (m.end < value.length && value[m.end] == ' ');
      final isValid = isComplete &&
          number.isNotEmpty &&
          int.tryParse(number) != null &&
          int.parse(number) >= 1 &&
          int.parse(number) <= 27; // during inning requires a number 1-27

      final range = TextRange(start: m.start, end: m.end);
      if (isValid) {
        validRanges.add(range);
      }
    }

    captionController.highlightedRanges = validRanges;
    captionController.invalidRanges = invalidRanges;
    _highlightedRanges = validRanges;

    // Progressive auto-selection: when a valid trailing player token is being typed,
    // select that player in the visual pickers below in real time.
    try {
      final trailingForward = RegExp(
        r'(?:^|\s)((?:h{1,2})|(?:v{1,2}))(\d{1,3})\s*$',
      );
      final trailingReverse = RegExp(
        r'(?:^|\s)(\d{1,3})((?:h{1,2})|(?:v{1,2}))\s*$',
      );
      String? teamToken;
      String? jersey;
      final m1 = trailingForward.firstMatch(value.toLowerCase());
      if (m1 != null) {
        teamToken = m1.group(1);
        jersey = m1.group(2);
      } else {
        final m2 = trailingReverse.firstMatch(value.toLowerCase());
        if (m2 != null) {
          jersey = m2.group(1);
          teamToken = m2.group(2);
        }
      }

      if (teamToken != null && jersey != null && jersey.isNotEmpty) {
        final bool isHome = teamToken.startsWith('h');
        final roster = isHome ? _homeRoster : _awayRoster;
        final exists = roster.any((p) => p.jerseyNumber == jersey);
        if (exists) {
          // If a different jersey was previously auto-selected for this team,
          // DO NOT unselect it. We want to keep previously selected players
          // when adding additional players via shortcodes.
          final lastAuto =
              isHome ? _autoSelectedHomeJersey : _autoSelectedAwayJersey;
          // Intentionally keep lastAuto selected to allow multiple selections
          // Select the current jersey
          _selectPlayerChipByNumber(
            isHomeTeam: isHome,
            jerseyNumber: jersey,
            isProgressive: true,
          );
        }
      }
    } catch (_) {
      // Best-effort progressive selection; ignore errors
    }

    setState(() {});
  }

  void _handleHrOptionInput(String value) {
    final token = value.trim().toLowerCase();
    if (token.isEmpty) return;
    final normalized = token.replaceAll(RegExp(r'[^a-z0-9]'), '');

    // Accept partials to be forgiving
    String? hrType;
    if ('solo'.startsWith(normalized)) {
      hrType = 'Solo';
    } else if ('tworun'.startsWith(normalized) ||
        normalized == '2' ||
        normalized == '2run') {
      hrType = 'Two-Run';
    } else if ('threerun'.startsWith(normalized) ||
        normalized == '3' ||
        normalized == '3run') {
      hrType = 'Three-Run';
    } else if ('grandslam'.startsWith(normalized) ||
        normalized == 'grand' ||
        normalized == 'gs') {
      hrType = 'Grand Slam';
    }

    if (hrType != null) {
      setState(() {
        _selectedVerb = 'Home Run';
        _selectedActionVerb = 'Home Run';
        _selectedHomeRunType = hrType;
        switch (hrType) {
          case 'Solo':
            _rbiCount = 1;
            break;
          case 'Two-Run':
            _rbiCount = 2;
            break;
          case 'Three-Run':
            _rbiCount = 3;
            break;
          case 'Grand Slam':
            _rbiCount = 4;
            break;
        }
      });
      _updateCaption();
    }
  }

  // Minimal chip selection helpers (safe no-ops if roster/players missing)
  void _selectPlayerChipByNumber({
    required bool isHomeTeam,
    required String jerseyNumber,
    bool isProgressive = false,
    bool affectFirstStar = true,
  }) {
    final roster = isHomeTeam ? _homeRoster : _awayRoster;
    final name = roster
        .firstWhere(
          (p) => p.jerseyNumber == jerseyNumber,
          orElse: () => Player(
            fullName: '',
            firstName: '',
            displayName: '',
            jerseyNumber: '',
          ),
        )
        .displayName;
    if (name.isEmpty) return;
    final set = isHomeTeam ? selectedHomePlayers : selectedAwayPlayers;
    set.add(name);

    // Optionally affect first star tracking
    if (affectFirstStar) {
      if (_firstTeamSelected == null) {
        _firstTeamSelected = isHomeTeam;
      }
      _firstPlayerSelected ??= _removeJerseyNumberFromName(name);
    }

    // Red star is determined by caption text order

    if (isHomeTeam) {
      _autoSelectedHomeJersey = jerseyNumber;
    } else {
      _autoSelectedAwayJersey = jerseyNumber;
    }
    // Immediately add the player's name to keywords if the toggle is on.
    // _reapplyVerbKeywordsIfEnabled (below) only fires when a verb is already
    // selected; this ensures names appear as soon as the player is clicked.
    if (_applyPlayerNamesToKeywordsEnabled && _showKeywordsField) {
      final kwName = _removeDiacritics(_removeJerseyNumberFromName(name));
      if (kwName.isNotEmpty) {
        final merged =
            mergeVerbKeywordFieldText(keywordsController.text, [kwName]);
        keywordsController.text = merged;
        keywordsController.selection =
            TextSelection.collapsed(offset: merged.length);
      }
    }

    setState(() {});
    _reapplyVerbKeywordsIfEnabled();
  }

  void _unselectAutoSelectedByToken({
    required bool isHomeTeam,
    required String jerseyNumber,
  }) {
    final roster = isHomeTeam ? _homeRoster : _awayRoster;
    final name = roster
        .firstWhere(
          (p) => p.jerseyNumber == jerseyNumber,
          orElse: () => Player(
            fullName: '',
            firstName: '',
            displayName: '',
            jerseyNumber: '',
          ),
        )
        .displayName;
    if (name.isEmpty) return;
    final set = isHomeTeam ? selectedHomePlayers : selectedAwayPlayers;
    set.remove(name);
    // Only clear the red star if this was truly the first selected player AND
    // we're removing the last remaining player, not just switching auto-selections
    // Red star tracking removed - determined by caption text order only
    if (isHomeTeam && _autoSelectedHomeJersey == jerseyNumber) {
      _autoSelectedHomeJersey = null;
    }
    if (!isHomeTeam && _autoSelectedAwayJersey == jerseyNumber) {
      _autoSelectedAwayJersey = null;
    }
    setState(() {});
  }

  Widget _buildSecondaryFieldCard(
      String label, TextEditingController controller) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Padding(
          padding: const EdgeInsets.only(left: 2, bottom: 0),
          child: Text(
            label,
            style: const TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w500,
              color: Colors.black87,
            ),
          ),
        ),
        TextField(
          controller: controller,
          minLines: 1,
          maxLines: 1,
          style: const TextStyle(fontSize: 11),
          decoration: InputDecoration(
            border: OutlineInputBorder(
              borderRadius: BorderRadius.circular(5),
              borderSide: BorderSide(
                color: Colors.grey.shade400,
              ),
            ),
            enabledBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(5),
              borderSide: BorderSide(
                color: Colors.grey.shade400,
              ),
            ),
            focusedBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(5),
              borderSide: BorderSide(
                color: Colors.blue.shade400,
                width: 2,
              ),
            ),
            contentPadding: const EdgeInsets.symmetric(
              horizontal: 6,
              vertical: 5,
            ),
            filled: true,
            fillColor: Colors.grey.shade50,
          ),
        ),
      ],
    );
  }

  /// Optional fields stacked vertically on the right.
  Widget _buildCaptionSecondaryFieldsRow() {
    if (!_showPersonalityField && !_showHeadlineField && !_showKeywordsField) {
      return const SizedBox.shrink();
    }

    final cards = <Widget>[];
    if (_showPersonalityField) {
      cards.add(_buildSecondaryFieldCard('PERSONALITY', personalityController));
    }
    if (_showHeadlineField) {
      cards.add(_buildSecondaryFieldCard('HEADLINE', headlineController));
    }
    if (_showKeywordsField) {
      cards.add(_buildSecondaryFieldCard('KEYWORDS', keywordsController));
    }

    final children = <Widget>[];
    for (var i = 0; i < cards.length; i++) {
      if (i > 0) children.add(const SizedBox(height: 6));
      children.add(Expanded(child: cards[i]));
    }
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: children,
    );
  }

