                                                color: Colors.grey.shade400,
                                              ),
                                            ),
                                            enabledBorder: OutlineInputBorder(
                                              borderRadius:
                                                  BorderRadius.circular(6),
                                              borderSide: BorderSide(
                                                color: Colors.grey.shade400,
                                              ),
                                            ),
                                            focusedBorder: OutlineInputBorder(
                                              borderRadius:
                                                  BorderRadius.circular(6),
                                              borderSide: BorderSide(
                                                color: Colors.blue.shade400,
                                                width: 2,
                                              ),
                                            ),
                                            contentPadding:
                                                const EdgeInsets.symmetric(
                                              horizontal: 6,
                                              vertical: 5,
                                            ),
                                            filled: true,
                                            fillColor: Colors.grey.shade50,
                                          ),
                                          inputFormatters: [
                                            HighlightedTokenDeletionFormatter(
                                              getRanges: () =>
                                                  _highlightedRanges,
                                              onTokenDeleted:
                                                  (deletedRange, tokenText) {
                                                // Update personality if this was a player expansion
                                                final playerName =
                                                    _tokenToPlayerName[
                                                        tokenText.trim()];
                                                if (playerName != null) {
                                                  _removePlayerFromPersonality(
                                                    playerName,
                                                  );
                                                  // Remove mapping for this exact token text
                                                  _tokenToPlayerName.remove(
                                                    tokenText.trim(),
                                                  );
                                                }

                                                // Rebuild highlight ranges after deletion
                                                final int removedLen =
                                                    deletedRange.end -
                                                        deletedRange.start;
                                                final List<TextRange> updated =
                                                    [];
                                                for (final r
                                                    in _highlightedRanges) {
                                                  // Skip the deleted range itself
                                                  if (r.start >=
                                                          deletedRange.start &&
                                                      r.end <=
                                                          deletedRange.end) {
                                                    continue;
                                                  }
                                                  if (r.start >=
                                                      deletedRange.end) {
                                                    updated.add(
                                                      TextRange(
                                                        start: r.start -
                                                            removedLen,
                                                        end: r.end - removedLen,
                                                      ),
                                                    );
                                                  } else {
                                                    updated.add(r);
                                                  }
                                                }
                                                _highlightedRanges = updated;
                                                (captionController
                                                        as HighlightingTextEditingController)
                                                    .highlightedRanges = updated;
                                                (captionController
                                                        as HighlightingTextEditingController)
                                                    .invalidRanges = [];
                                                setState(() {});
                                              },
                                            ),
                                          ],
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                                if (_showHeadlineField ||
                                    _showKeywordsField ||
                                    _showPersonalityField) ...[
                                  const SizedBox(width: 6),
                                  Expanded(
                                    flex: 5,
                                    child: _buildCaptionSecondaryFieldsRow(),
                                  ),
                                ],
                          ],
                        ),
                      ),
                      // No gap between caption and firebar
                      // Action buttons are now beside the magic bar
                      // (Old action button container removed)
                      // Firebar container aligned to the left with FTP buttons on the right
                      Align(
                        alignment: Alignment.centerLeft,
                        child: Row(
