                                    : Row(
                                        mainAxisAlignment:
                                            MainAxisAlignment.start,
                                        children: [
                                          // First column - Magic bar with help button (hidden when _showFirebar is false)
                                          if (_showFirebar)
                                            Expanded(
                                              flex: 6,
                                              child: Row(
