  /// Shared category header styles (verb grid and Home Run sub-panels).
  Widget _categorySectionTitle(
    String displayTitle,
    int categoryNumber, {
    bool favoritesStyle = false,
    bool showReorderHint = false,
  }) {
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 4),
      decoration: BoxDecoration(
        color: favoritesStyle ? Colors.amber.shade200 : Colors.grey.shade200,
        borderRadius: BorderRadius.circular(3),
      ),
      child: Row(
        children: [
          if (showReorderHint) ...[
            Icon(Icons.drag_indicator, size: 14, color: Colors.grey.shade700),
            const SizedBox(width: 4),
          ],
          Expanded(
            child: Text(
              '$categoryNumber. $displayTitle',
              style: const TextStyle(
                fontSize: 11,
                fontWeight: FontWeight.w600,
                color: Colors.black87,
              ),
            ),
          ),
        ],
      ),
    );
  }

  /// Verb chips for one category column (used by draggable grid and [_buildCategoryContent]).
  List<Widget> _verbChildrenForCategoryName(String categoryName) {
    if (categoryName == 'Favorites') {
      return [
        ..._favoriteVerbs.toList().asMap().entries.map(
              (e) => _buildVerbOption(e.value, verbNumber: e.key + 1),
            ),
        ...List.generate(
          10 - _favoriteVerbs.length,
          (index) => _buildVerbOption(''),
        ),
      ];
    }
    final verbs = verbCategories[categoryName] ?? [];
    return verbs
        .asMap()
        .entries
        .map((e) => _buildVerbOption(e.value, verbNumber: e.key + 1))
        .toList();
  }

  Widget _buildDraggableCategories() {
    // Split categories into two rows of 3 columns each
    List<String> firstRow = _categoryOrder.take(3).toList();
    List<String> secondRow = _categoryOrder.skip(3).toList();

    final column = Column(
      children: [
        // First row: 3 columns
        Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: firstRow.map((categoryName) {
            final index = _categoryOrder.indexOf(categoryName);
            return Expanded(
              key: ValueKey('cat_${categoryName}_$index'),
              child: _buildDraggableCategoryCard(categoryName),
            );
          }).toList(),
        ),
        const SizedBox(height: 2),
        // Second row: 3 columns
        Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: secondRow.map((categoryName) {
            final index = _categoryOrder.indexOf(categoryName);
            return Expanded(
              key: ValueKey('cat_${categoryName}_$index'),
              child: _buildDraggableCategoryCard(categoryName),
            );
          }).toList(),
        ),
      ],
    );
    // "Caption by numbers": click verb area then type two digits (category, verb) to select
    return Listener(
      onPointerDown: (_) => _verbNumbersFocusNode.requestFocus(),
      child: Focus(
        focusNode: _verbNumbersFocusNode,
        onKeyEvent: (node, event) {
          final handled = _handleVerbNumberKey(event);
          return handled ? KeyEventResult.handled : KeyEventResult.ignored;
        },
        child: column,
      ),
    );
  }

  Widget _buildDraggableCategoryCard(String categoryName) {
    final categoryNumber = _categoryOrder.indexOf(categoryName) + 1;
    final displayTitle =
        categoryName == 'Favorites' ? 'Favorites' : categoryName;
    return DragTarget<String>(
      onAccept: (draggedCategory) {
        setState(() {
          final draggedIndex = _categoryOrder.indexOf(draggedCategory);
          final targetIndex = _categoryOrder.indexOf(categoryName);

          if (draggedIndex != -1 &&
              targetIndex != -1 &&
              draggedIndex != targetIndex) {
            // Swap the categories
            _categoryOrder[draggedIndex] = categoryName;
            _categoryOrder[targetIndex] = draggedCategory;

            // Save the new category order immediately for current sport
            _preferencesService.saveCategoryOrder(_categoryOrder,
                sport: _currentSport);
          }
        });
      },
      builder: (context, candidateData, rejectedData) {
        return LayoutBuilder(
          builder: (context, constraints) {
            // Long-press must attach to the title bar only: verb chips use
            // GestureDetector(onTapDown) and would win the gesture arena over
            // a parent LongPressDraggable on the full column.
            return Container(
              margin: const EdgeInsets.only(right: 1),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  LongPressDraggable<String>(
                    data: categoryName,
                    delay: const Duration(milliseconds: 400),
                    hapticFeedbackOnStart: false,
                    feedback: Material(
                      elevation: 6,
                      child: SizedBox(
                        width: constraints.maxWidth,
                        child: _categorySectionTitle(
                          displayTitle,
                          categoryNumber,
                          favoritesStyle: categoryName == 'Favorites',
                          showReorderHint: true,
                        ),
                      ),
                    ),
                    childWhenDragging: Opacity(
                      opacity: 0.35,
                      child: _categorySectionTitle(
                        displayTitle,
                        categoryNumber,
                        favoritesStyle: categoryName == 'Favorites',
                        showReorderHint: true,
                      ),
                    ),
                    child: _categorySectionTitle(
                      displayTitle,
                      categoryNumber,
                      favoritesStyle: categoryName == 'Favorites',
                      showReorderHint: true,
                    ),
                  ),
                  ..._verbChildrenForCategoryName(categoryName),
                ],
              ),
            );
          },
        );
      },
    );
  }

  Widget _buildCategoryContent(String categoryName) {
    final categoryNumber = _categoryOrder.indexOf(categoryName) + 1;
    final displayTitle =
        categoryName == 'Favorites' ? 'Favorites' : categoryName;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _categorySectionTitle(
          displayTitle,
          categoryNumber,
          favoritesStyle: categoryName == 'Favorites',
          showReorderHint: false,
        ),
        ..._verbChildrenForCategoryName(categoryName),
      ],
    );
  }

  bool _handleVerbNumberKey(KeyEvent event) {
    if (event is! KeyDownEvent) return false;
    final k = event.logicalKey;
    int? digit;
    if (k == LogicalKeyboardKey.digit1 || k == LogicalKeyboardKey.numpad1)
      digit = 1;
    else if (k == LogicalKeyboardKey.digit2 || k == LogicalKeyboardKey.numpad2)
      digit = 2;
    else if (k == LogicalKeyboardKey.digit3 || k == LogicalKeyboardKey.numpad3)
      digit = 3;
    else if (k == LogicalKeyboardKey.digit4 || k == LogicalKeyboardKey.numpad4)
      digit = 4;
    else if (k == LogicalKeyboardKey.digit5 || k == LogicalKeyboardKey.numpad5)
      digit = 5;
    else if (k == LogicalKeyboardKey.digit6 || k == LogicalKeyboardKey.numpad6)
      digit = 6;
    else if (k == LogicalKeyboardKey.digit7 || k == LogicalKeyboardKey.numpad7)
      digit = 7;
    else if (k == LogicalKeyboardKey.digit8 || k == LogicalKeyboardKey.numpad8)
      digit = 8;
    else if (k == LogicalKeyboardKey.digit9 || k == LogicalKeyboardKey.numpad9)
      digit = 9;
    else if (k == LogicalKeyboardKey.digit0 || k == LogicalKeyboardKey.numpad0)
      digit = 0;
    if (digit == null) return false;

    _numberBufferTimer?.cancel();
    _numberBuffer += digit.toString();
    if (_numberBuffer.length >= 2) {
      final cat = int.tryParse(_numberBuffer[0]) ?? 0;
      final verbNum =
          _numberBuffer[1] == '0' ? 10 : int.tryParse(_numberBuffer[1]) ?? 0;
      _numberBuffer = '';
      _selectVerbByCategoryAndIndex(cat, verbNum);
      return true;
    }
    _numberBufferTimer = Timer(const Duration(milliseconds: 1500), () {
      if (mounted) setState(() => _numberBuffer = '');
    });
    return true;
  }

  /// Called from caption builder screen when Option+digit shortcut is used (no focus needed).
  void selectVerbByCategoryAndIndex(int category1Based, int verb1Based) {
    _selectVerbByCategoryAndIndex(category1Based, verb1Based);
  }

  /// Keyboard Fire: set verb and update caption without showing any dialog.
  /// Use this when the verb is picked from the Keyboard Fire panel so only the panel’s Save/Copy/FTP popup appears.
  void selectVerbByCategoryAndIndexFromKeyboardFire(
      int category1Based, int verb1Based,
      {bool suppressCaptionUpdate = false}) {
    final order = effectiveCategoryOrder;
    if (category1Based < 1 || category1Based > order.length) return;
    final categoryName = order[category1Based - 1];
    final List<String> verbList = categoryName == 'Favorites'
        ? _favoriteVerbs.toList()
        : (verbCategories[categoryName] ?? []);
    final verbIndex = verb1Based == 0 ? 9 : verb1Based - 1;
    if (verbIndex < 0 || verbIndex >= verbList.length) return;
    final verb = verbList[verbIndex];
    if (verb.isEmpty) return;

    if (_selectedVerb == verb) {
      setState(() {
        _selectedVerb = null;
        _selectedActionVerb = null;
        _selectedHomeRunType = null;
        _selectedTagsAction = null;
        _selectedBase = null;
        _rbiCount = null;
        _selectedRbiInning = null;
      });
      if (!suppressCaptionUpdate) _updateCaption();
    } else {
      setState(() {
        _selectedVerb = verb;
        _selectedActionVerb = verb;
        _selectedBase = null;
        _selectedHomeRunType = null;
        _rbiCount = null;
      });
      _mergeVerbKeywordsIntoFieldIfEnabled(verb);
      if (!suppressCaptionUpdate) _updateCaption();
    }
  }

