  /// Called from keyboard fire panel: toggle favorite and persist.
  Future<void> toggleFavoriteVerbFromKeyboardFire(String verb) async {
    if (_favoriteVerbs.contains(verb)) {
      _favoriteVerbs.remove(verb);
    } else {
      _favoriteVerbs.add(verb);
    }
    await _preferencesService.saveFavoriteVerbs(_favoriteVerbs,
        sport: _currentSport);
    if (mounted) setState(() {});
  }

  /// Called from keyboard fire panel: whether a verb is in favorites.
  bool isFavoriteVerbFromKeyboardFire(String verb) =>
      _favoriteVerbs.contains(verb);

  /// Called from keyboard fire panel: whether this verb has an override (so "Delete verb" can revert it).
  bool hasVerbOverrideFromKeyboardFire(String displayLabelOrKey) {
    final s = displayLabelOrKey.trim();
    if (s.isEmpty) return false;
    if (_verbOverrides.containsKey(s)) return true;
    for (final entry in _verbOverrides.entries) {
      final label = entry.value['label'] as String?;
      if (label != null && label.trim() == s) return true;
    }
    return false;
  }

  /// Called from keyboard fire panel: remove verb override so the verb reverts to its default display name.
  /// [displayLabelOrKey] is the verb string shown in the list (display label) or the original key.
  /// Returns true if an override was removed.
  Future<bool> deleteVerbOverrideFromKeyboardFire(
      String displayLabelOrKey) async {
    final s = displayLabelOrKey.trim();
    if (s.isEmpty) return false;

    // Resolve the canonical verb key (the built-in name, before any override label)
    String canonicalVerb = s;
    for (final entry in _verbOverrides.entries) {
      final label = entry.value['label'] as String?;
      if (label != null && label.trim() == s) {
        canonicalVerb = entry.key;
        break;
      }
    }

    // Add to deleted verbs so it is hidden from the list
    await _preferencesService.addDeletedVerb(canonicalVerb,
        sport: _currentSport);
    _deletedVerbs =
        await _preferencesService.getDeletedVerbs(sport: _currentSport);

    // Also clear any verb override so it doesn't ghost around
    if (_verbOverrides.containsKey(canonicalVerb)) {
      await _preferencesService.removeVerbOverride(canonicalVerb,
          sport: _currentSport);
      _verbOverrides =
          await _preferencesService.getVerbOverrides(sport: _currentSport);
    }

    if (mounted) setState(() {});
    widget.onVerbOverridesChanged?.call();
    return true;
  }

  /// Resolve verb to its display label (from verb overrides if edited), for use in lists.
  String _verbDisplayLabel(String verb) {
    if (_verbOverrides.containsKey(verb)) {
      final label = _verbOverrides[verb]!['label'] as String?;
      if (label != null && label.isNotEmpty) return label;
    }
    return verb;
  }

  /// The effective category order for the current sport: filters out categories that don't
  /// exist in [verbCategories] (e.g. 'Running' doesn't exist for basketball/hockey), ensures
  /// 'Favorites' is always included, and falls back to the sport default if empty.
  /// This is the single source of truth used by [keyboardFireVerbList] and all category-index lookups.
  List<String> get effectiveCategoryOrder {
    final order = _categoryOrder
        .where((cat) => cat == 'Favorites' || verbCategories.containsKey(cat))
        .toList();
    List<String> effective = order.isNotEmpty
        ? List<String>.from(order)
        : List<String>.from(categoryOrder);
    if (!effective.contains('Favorites')) {
      effective = [...effective, 'Favorites'];
    }
    return effective;
  }

  /// Verb list for keyboard fire dialog: category number, name, and ordered verb strings.
  /// Uses sport-aware category order (filters _categoryOrder to valid categories, else default).
  /// Favorites is always included so it appears in the Keyboard Fire panel.
  /// Applies verb overrides so edited display names (e.g. "Goes to the Net Against") show correctly.
  List<Map<String, dynamic>> get keyboardFireVerbList {
    final effectiveOrder = effectiveCategoryOrder;
    final list = <Map<String, dynamic>>[];
    for (var i = 0; i < effectiveOrder.length; i++) {
      final cat = effectiveOrder[i];
      final catNum = i + 1;
      final rawVerbs = cat == 'Favorites'
          ? _favoriteVerbs.toList()
          : (verbCategories[cat] ?? <String>[]);
      final verbs = rawVerbs.map(_verbDisplayLabel).toList();
      list.add(
          <String, dynamic>{'number': catNum, 'name': cat, 'verbs': verbs});
    }
    return list;
  }

  // ── Public helpers for KeyboardFirePanel action bar ──────────────────────

  void reorderCategories(int fromIndex, int toIndex) {
    final effective = effectiveCategoryOrder;
    if (fromIndex < 0 || fromIndex >= effective.length) return;
    if (toIndex < 0 || toIndex >= effective.length) return;
    if (fromIndex == toIndex) return;
    final fromCat = effective[fromIndex];
    final toCat = effective[toIndex];
    final realFrom = _categoryOrder.indexOf(fromCat);
    final realTo = _categoryOrder.indexOf(toCat);
    if (realFrom == -1 || realTo == -1) return;
    setState(() {
      _categoryOrder.removeAt(realFrom);
      _categoryOrder.insert(realTo, fromCat);
    });
    _preferencesService.saveCategoryOrder(_categoryOrder, sport: _currentSport);
  }

