  // Function to find the shortest unique prefix for a verb
  String _getShortestUniquePrefix(String verb, List<String> allVerbs) {
    for (int i = 1; i <= verb.length; i++) {
      String prefix = verb.substring(0, i).toLowerCase();
      bool isUnique = true;

      for (String otherVerb in allVerbs) {
        if (otherVerb != verb && otherVerb.toLowerCase().startsWith(prefix)) {
          isUnique = false;
          break;
        }
      }

      if (isUnique) {
        return verb.substring(0, i);
      }
    }
    return verb; // Fallback to full verb if no unique prefix found
  }

  Widget _buildVerbOption(String verb, {int? verbNumber}) {
    // Show blank chip for empty placeholder verbs
    if (verb.isEmpty) {
      return Container(
        width: double.infinity,
        height: 36,
        padding: const EdgeInsets.symmetric(horizontal: 1, vertical: 6),
        margin: const EdgeInsets.only(bottom: 1),
        decoration: BoxDecoration(
          color: Colors.grey.shade50,
          borderRadius: BorderRadius.circular(3),
          border: Border.all(color: Colors.grey.shade200, width: 0.5),
        ),
        child: const Center(
          child: Text(
            '',
            style: TextStyle(
              fontSize: 12,
              fontWeight: FontWeight.w400,
              color: Colors.transparent,
            ),
          ),
        ),
      );
    }

    final isSelected = _selectedVerb == verb;
    final isSticky = _stickyVerb == verb;

    // Get all verbs for prefix calculation
    List<String> allVerbs = [];
    for (List<String> verbs in verbCategories.values) {
      allVerbs.addAll(verbs);
    }

    // Get the shortest unique prefix for this verb
    String shortestPrefix = _getShortestUniquePrefix(verb, allVerbs);
    return GestureDetector(
      onSecondaryTapDown: (details) {
        // Show context menu on right-click
        final RenderBox overlay =
            Overlay.of(context).context.findRenderObject() as RenderBox;
        final RelativeRect position = RelativeRect.fromRect(
          Rect.fromPoints(
            details.globalPosition,
            details.globalPosition,
          ),
          Offset.zero & overlay.size,
        );

        showMenu<String>(
          context: context,
          position: position,
          items: [
            PopupMenuItem<String>(
              value: 'favorite',
              child: Row(
                children: [
                  Icon(
                    _favoriteVerbs.contains(verb)
                        ? Icons.star
                        : Icons.star_border,
                    size: 18,
                    color: _favoriteVerbs.contains(verb)
                        ? Colors.amber
                        : Colors.grey,
                  ),
                  const SizedBox(width: 8),
                  Text(_favoriteVerbs.contains(verb)
                      ? 'Remove from Favorites'
                      : 'Add to Favorites'),
                ],
              ),
            ),
            const PopupMenuItem<String>(
              value: 'edit',
              child: Row(
                children: [
                  Icon(Icons.edit, size: 18, color: Colors.grey),
                  SizedBox(width: 8),
                  Text('Edit Wording'),
                ],
              ),
            ),
            const PopupMenuItem<String>(
              value: 'delete_verb',
              child: Row(
                children: [
                  Icon(Icons.delete_outline, size: 18, color: Colors.grey),
                  SizedBox(width: 8),
                  Text('Delete verb'),
                ],
              ),
            ),
          ],
        ).then((value) async {
          if (value == 'favorite') {
            setState(() {
              if (_favoriteVerbs.contains(verb)) {
                _favoriteVerbs.remove(verb);
              } else {
                _favoriteVerbs.add(verb);
              }
            });
            await _preferencesService.saveFavoriteVerbs(_favoriteVerbs,
                sport: _currentSport);
          } else if (value == 'edit') {
            _showEditVerbDialog(verb);
          } else if (value == 'delete_verb') {
            await deleteVerbOverrideFromKeyboardFire(verb);
            if (mounted) {
              ScaffoldMessenger.of(context).showSnackBar(
                const SnackBar(content: Text('Verb removed from list.')),
              );
            }
          }
        });
      },
      onTapDown: (TapDownDetails details) {
        // Cmd+click: sticky verb (classic behavior) — stick until Cmd+click same verb again
        final isMetaPressed = HardwareKeyboard.instance.isMetaPressed;

        if (isMetaPressed) {
          setState(() {
            if (_stickyVerb == verb) {
              _stickyVerb = null;
              _selectedVerb = null;
              _selectedActionVerb = null;
              _selectedHomeRunType = null;
              _selectedTagsAction = null;
              _selectedBase = null;
              _rbiCount = null;
              _selectedRbiInning = null;
            } else {
              _stickyVerb = verb;
              _selectedVerb = verb;
              _selectedActionVerb = verb;
              _selectedHomeRunType = null;
              _selectedTagsAction = null;
              _selectedBase = null;
              _rbiCount = null;
              _selectedRbiInning = null;
            }
          });
          _updateCaption();
          if (_stickyVerb == verb) {
            _mergeVerbKeywordsIntoFieldIfEnabled(verb);
          }
          return;
        }

        // Normal click: clear sticky
        setState(() => _stickyVerb = null);

        // Store tap position for positioning the popup
        final RenderBox renderBox = context.findRenderObject() as RenderBox;
        final localPosition = renderBox.globalToLocal(details.globalPosition);
        final globalPosition = renderBox.localToGlobal(localPosition);

        if (isSelected) {
          // Tap again on already-selected verb → deselect + clear caption
          setState(() {
            _selectedVerb = null;
            _selectedActionVerb = null;
            _selectedHomeRunType = null;
            _selectedTagsAction = null;
            _selectedBase = null;
            _rbiCount = null;
            _selectedRbiInning = null;
          });
          _updateCaption();
          return;
        }

        // Immediately highlight the verb (like player selection)
        setState(() {
          _selectedVerb = verb;
          _selectedActionVerb = verb;
          _selectedHomeRunType = null;
          _selectedTagsAction = null;
          _selectedBase = null;
          _rbiCount = null;
          _selectedRbiInning = null;
        });
        _mergeVerbKeywordsIntoFieldIfEnabled(verb);
        _updateCaption();

        // Open any relevant popup for extra options (inning, hitting details, etc.)
        if (_shouldShowInningSelector(verb)) {
          _showCompactInningSelector(globalPosition, verb);
        } else if (_shouldShowFullPopupInterface(verb)) {
          _showHittingPopup(globalPosition, verb);
        } else {
          _showSimpleVerbPopup(globalPosition, verb);
        }
      },
      child: Container(
        width: double.infinity, // Dynamic width to fit container
        height: 36, // Further increased height for bigger chips
        padding: const EdgeInsets.symmetric(horizontal: 2, vertical: 6),
        margin: const EdgeInsets.only(bottom: 1),
        decoration: BoxDecoration(
          color: isSticky
              ? const Color(0xFFE3EDFF)
              : (isSelected ? const Color(0xFFDBEAFF) : Colors.grey.shade50),
          borderRadius: BorderRadius.circular(3),
          border: Border.all(
            color: isSticky
                ? const Color(0xFF0052CC)
                : (isSelected ? const Color(0xFF4A90E2) : Colors.grey.shade300),
            width: (isSelected || isSticky) ? 1.5 : 0.5,
          ),
        ),
        child: Center(
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (verbNumber != null)
                Padding(
                  padding: const EdgeInsets.only(right: 4),
                  child: Container(
                    padding:
                        const EdgeInsets.symmetric(horizontal: 4, vertical: 1),
                    decoration: BoxDecoration(
                      color: isSelected
                          ? const Color(0xFF4A90E2)
                          : Colors.grey.shade500,
                      borderRadius: BorderRadius.circular(3),
                    ),
                    child: Text(
                      '$verbNumber',
                      style: const TextStyle(
                        fontSize: 9,
                        color: Colors.white,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ),
                ),
              Flexible(
                child: Builder(
                  builder: (context) {
                    String typed = _magicBarVerbInput;
                    // Only use trailing letters for verb matching (ignore digits like in "h27")
                    final RegExpMatch? lettersMatch = RegExp(
                      r'([a-zA-Z]+)$',
                    ).firstMatch(typed);
                    final String typedLetters =
                        lettersMatch?.group(1)?.toLowerCase() ?? '';

                    // Debug output
                    // print(
                    //     'DEBUG: Verb: $verb, Typed: "$typed", Letters: "$typedLetters"');

                    // Calculate the shortcut letters for this verb
                    String shortcutLetters = '';
                    final words = verb.split(' ');
                    final filtered = words
                        .where((w) =>
                            w.trim().isNotEmpty && w.toLowerCase() != 'the')
                        .toList();

                    if (filtered.isEmpty) {
                      // Fallback if no valid words found
                      shortcutLetters = verb.length >= 3
                          ? verb.substring(0, 3).toLowerCase()
                          : verb.toLowerCase();
                    } else if (filtered.length > 1) {
                      // Multi-word verb: use acronym
                      shortcutLetters =
                          filtered.map((w) => w[0].toLowerCase()).join();
                    } else {
                      // Single word verb: use first 2-3 letters
                      final first = filtered.first.toLowerCase();
                      shortcutLetters =
                          first.length >= 3 ? first.substring(0, 3) : first;
                    }

                    // Determine what to highlight based on what's typed
                    String displayPrefix;
                    List<int> firstLetterPositions = [];

                    if (filtered.length > 1) {
                      // Multi-word verb: find positions of first letters to highlight
                      int currentPos = 0;

                      for (int i = 0; i < words.length; i++) {
                        String word = words[i].trim();
                        if (word.isNotEmpty && word.toLowerCase() != 'the') {
                          // Find the position of the first letter in this word
                          int wordStart = currentPos +
                              (i > 0 ? 1 : 0); // Account for space before word
                          int firstLetterPos =
                              wordStart + word.indexOf(word[0]);
                          firstLetterPositions.add(firstLetterPos);
                        }
                        currentPos += word.length +
                            (i > 0 ? 1 : 0); // Add word length + space
                      }

                      if (typedLetters.isNotEmpty &&
                          shortcutLetters.startsWith(typedLetters)) {
                        // User is typing the shortcut - highlight the first letters they've typed
                        int lettersToHighlight = typedLetters.length;
                        if (lettersToHighlight <= firstLetterPositions.length) {
                          displayPrefix = verb.substring(
                            0,
                            firstLetterPositions[lettersToHighlight - 1] + 1,
                          );
                        } else {
                          displayPrefix = verb.substring(
                            0,
                            firstLetterPositions.last + 1,
                          );
                        }
                      } else {
                        // Show all first letters
                        displayPrefix = verb.substring(
                          0,
                          firstLetterPositions.last + 1,
                        );
                      }
                    } else {
                      // Single word verb: use first 2-3 letters
                      if (typedLetters.isNotEmpty &&
                          shortcutLetters.startsWith(typedLetters)) {
                        // User is typing the shortcut - highlight what they've typed
                        final int len = typedLetters.length < verb.length
                            ? typedLetters.length
                            : verb.length;
                        displayPrefix = verb.substring(0, len);
                      } else if (typedLetters.isEmpty) {
                        // No typing - show the shortcut letters
                        displayPrefix =
                            verb.substring(0, shortcutLetters.length);
                      } else {
                        // User typed something else - show shortcut letters
                        displayPrefix =
                            verb.substring(0, shortcutLetters.length);
                      }
                    }

                    if (filtered.length > 1) {
                      // Multi-word verb: show fire emoji with shortcut after word
                      if (_magicBarFocusNode.hasFocus) {
                        return RichText(
                          maxLines: 2,
                          overflow: TextOverflow.visible,
                          text: TextSpan(
                            children: [
                              TextSpan(
                                text: _getVerbDisplayText(verb),
                                style: TextStyle(
                                  fontSize: 10,
                                  fontWeight: isSelected
                                      ? FontWeight.w600
                                      : FontWeight.w500,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.grey.shade700,
                                ),
                              ),
                              TextSpan(
                                text: ' 🔥$shortcutLetters',
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: FontWeight.w700,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.black87,
                                ),
                              ),
                              if (_favoriteVerbs.contains(verb))
                                TextSpan(
                                  text: ' ⭐',
                                  style: TextStyle(
                                    fontSize: 11,
                                    color: Colors.amber.shade600,
                                  ),
                                ),
                            ],
                          ),
                        );
                      } else {
                        return RichText(
                          text: TextSpan(
                            children: [
                              TextSpan(
                                text: _getVerbDisplayText(verb),
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: isSelected
                                      ? FontWeight.w600
                                      : FontWeight.w500,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.grey.shade700,
                                ),
                              ),
                              if (_favoriteVerbs.contains(verb))
                                TextSpan(
                                  text: ' ⭐',
                                  style: TextStyle(
                                    fontSize: 11,
                                    color: Colors.amber.shade600,
                                  ),
                                ),
                            ],
                          ),
                          maxLines: 2,
                          overflow: TextOverflow.visible,
                        );
                      }
                    } else {
                      // Single word verb: show fire emoji with shortcut after word
                      if (_magicBarFocusNode.hasFocus) {
                        return RichText(
                          maxLines: 2,
                          overflow: TextOverflow.visible,
                          text: TextSpan(
                            children: [
                              TextSpan(
                                text: _getVerbDisplayText(verb),
                                style: TextStyle(
                                  fontSize: 10,
                                  fontWeight: isSelected
                                      ? FontWeight.w600
                                      : FontWeight.w500,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.grey.shade700,
                                ),
                              ),
                              TextSpan(
                                text: ' 🔥$shortcutLetters',
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: FontWeight.w700,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.black87,
                                ),
                              ),
                              if (_favoriteVerbs.contains(verb))
                                TextSpan(
                                  text: ' ⭐',
                                  style: TextStyle(
                                    fontSize: 11,
                                    color: Colors.amber.shade600,
                                  ),
                                ),
                            ],
                          ),
                        );
                      } else {
                        // Firebar inactive – normal styling
                        return RichText(
                          text: TextSpan(
                            children: [
                              TextSpan(
                                text: _getVerbDisplayText(verb),
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: isSelected
                                      ? FontWeight.w600
                                      : FontWeight.w500,
                                  color: isSelected
                                      ? const Color(0xFF0052CC)
                                      : Colors.grey.shade700,
                                ),
                              ),
                              if (_favoriteVerbs.contains(verb))
                                TextSpan(
                                  text: ' ⭐',
                                  style: TextStyle(
                                    fontSize: 11,
                                    color: Colors.amber.shade600,
                                  ),
                                ),
                            ],
                          ),
                          maxLines: 2,
                          overflow: TextOverflow.visible,
                        );
                      }
                    }
                  },
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildCompactVerbChip(String verb, String label) {
    final isSelected = _selectedVerb == verb;
    return GestureDetector(
      onTap: () {
        setState(() {
          if (isSelected) {
            _selectedVerb = null;
            _selectedActionVerb = null; // Clear action verb when deselecting
            _selectedHomeRunType = null;
            _selectedTagsAction = null; // Clear tags action when deselecting
            _selectedBase = null; // Clear selected base when deselecting
            _rbiCount = null;
            _selectedRbiInning = null;
            _isBatterRunning = false;
          } else {
            _selectedVerb = verb;
            _selectedActionVerb = verb; // Store for caption generation
            _selectedHomeRunType = null;
            _rbiCount = null;
            _selectedRbiInning = null;
            _isBatterRunning = false;
          }
        });
        if (!isSelected &&
            (_selectedVerb == verb && _selectedActionVerb == verb)) {
          _mergeVerbKeywordsIntoFieldIfEnabled(verb);
        }
        _updateCaption();
      },
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 4, vertical: 5),
        decoration: BoxDecoration(
          color: isSelected ? Colors.grey.shade300 : Colors.grey.shade100,
          borderRadius: BorderRadius.circular(8),
          border: Border.all(
            color: isSelected ? Colors.grey.shade400 : Colors.grey.shade300,
            width: 0.5,
          ),
        ),
        child: Text(
          label,
          style: TextStyle(
            fontSize: 11,
            fontWeight: FontWeight.w500,
            color: isSelected ? Colors.grey.shade800 : Colors.grey.shade700,
          ),
        ),
      ),
    );
  }

  Widget _buildCompactHomeRunTypeChip(String hrType, String label) {
    final isSelected = _selectedHomeRunType == hrType;
    return GestureDetector(
      onTap: () {
        setState(() {
          if (isSelected) {
            _selectedHomeRunType = null;
          } else {
            _selectedHomeRunType = hrType;
            switch (hrType) {
              case 'Solo':
                _rbiCount = 1;
                break;
              case 'Two-Run':
                _rbiCount = 2;
                break;
              case 'Three-Run':
                _rbiCount = 3;
                break;
              case 'Grand Slam':
                _rbiCount = 4;
                break;
            }
          }
        });
        _updateCaption();
      },
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 4, vertical: 2),
        decoration: BoxDecoration(
          color: isSelected ? Colors.grey.shade300 : Colors.grey.shade100,
          borderRadius: BorderRadius.circular(8),
          border: Border.all(
            color: isSelected ? Colors.grey.shade400 : Colors.grey.shade300,
            width: 0.5,
          ),
        ),
        child: Text(
          label,
          style: TextStyle(
            fontSize: 13,
            fontWeight: FontWeight.w500,
            color: isSelected ? Colors.grey.shade800 : Colors.grey.shade700,
          ),
        ),
      ),
    );
  }

  bool _shouldShowInningSelector(String verb) {
    // Define which verbs ONLY need inning/period selection (no other options)
    const verbsNeedingOnlyInning = {
      // Baseball verbs
      'At Bat',
      'Pitching',
      'Swings',
      'Bunts',
      'Hit by Pitch',
      'Walks',
      'Catches',
      'Throws',
      'Groundball',
      'Double Play',
      'Triple Play',
      'Steals',
      'Slides',
      'Runs',
      'Rounds',
      'Fielding Position',
      'Looks On',
      'Walks Off Field',
      'Runs Off Field',
      'Takes the Field',
      'Comes Off the Field',
      'Strikeout',
      // Hockey verbs
      'Shoots',
      'Scores',
      'Passes',
      'Skates',
      'Battles',
      'Faceoff',
      'Goes to the Net',
      'Power Play',
      'Breakaway',
      'Blocks',
      'Saves',
      'Handles the Puck',
      'Stands in Net',
      'Guards the Net',
      'Clears',
      'Checks',
      'Defends',
      'Warm Ups',
      'Takes the Ice',
      'Comes Off the Ice',
      'National Anthem',
      'Stretching',
      'Bench',
      'Celebrates',
      'Celebrates a Goal',
      'Dejection',
      'Post Game Win',
      'Post Game Loss',
    };

    return verbsNeedingOnlyInning.contains(verb);
  }

  bool _shouldShowFullPopupInterface(String verb) {
    // Define which verbs should show a full popup interface (like Home Run)
    const verbsNeedingFullPopup = {
      'Home Run',
      'Single',
      'Double',
      'Triple',
    };

    return verbsNeedingFullPopup.contains(verb);
  }

