  List<Widget> _buildHomeRunOptionsForPopup(
      void Function(void Function()) setDialogState) {
    final options = [
      {'label': 'Celebrates', 'value': 'celebrates'},
      {'label': 'Celebrates in Dugout', 'value': 'celebrates_in_dugout'},
      {'label': 'Trots the Bases', 'value': 'trots_the_bases'},
    ];

    return options.map((option) {
      final isSelected = _selectedActionVerb == option['value'];
      return GestureDetector(
        onTap: () {
          setState(() {
            _selectedActionVerb = _selectedActionVerb == option['value']
                ? 'Home Run'
                : option['value'] as String;
          });
          setDialogState(() {});
          _updateCaption();
        },
        child: Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
          margin: const EdgeInsets.only(bottom: 2),
          decoration: BoxDecoration(
            color: isSelected ? Colors.grey.shade300 : Colors.grey.shade50,
            borderRadius: BorderRadius.circular(3),
            border: Border.all(color: Colors.grey.shade300, width: 0.5),
          ),
          child: Text(
            option['label'] as String,
            style: TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w500,
              color: Colors.grey.shade700,
            ),
          ),
        ),
      );
    }).toList();
  }

  List<Widget> _buildHittingOptionsForPopup(
      void Function(void Function()) setDialogState, String verbName) {
    List<Map<String, String>> options = [
      {'label': 'Celebrates', 'value': 'celebrates'},
      {'label': 'Runs the Base Paths', 'value': 'runs_base_paths'},
    ];

    // Add "Slides into Base" option for Double and Triple (not Single)
    if (verbName != 'Single') {
      options.add({'label': 'Slides into Base', 'value': 'slides_into_base'});
    }

    return options.map((option) {
      final isSelected = _selectedHittingAction == option['value'];
      return GestureDetector(
        onTap: () {
          setState(() {
            _selectedHittingAction = _selectedHittingAction == option['value']
                ? null
                : option['value'] as String;
            _selectedVerb = verbName;
            _selectedActionVerb = verbName;
          });
          setDialogState(() {});
          _updateCaption();
        },
        child: Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
          margin: const EdgeInsets.only(bottom: 2),
          decoration: BoxDecoration(
            color: isSelected ? Colors.grey.shade300 : Colors.grey.shade50,
            borderRadius: BorderRadius.circular(3),
            border: Border.all(color: Colors.grey.shade300, width: 0.5),
          ),
          child: Text(
            option['label'] as String,
            style: TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w500,
              color: Colors.grey.shade700,
            ),
          ),
        ),
      );
    }).toList();
  }

  Widget _buildInningGridForPopup(
      void Function(void Function()) setDialogState, String verbName) {
    // Determine which innings to show based on current page
    int currentPage = _extraInningsPage;
    List<int> inningsToShow;

    if (currentPage == 0) {
      inningsToShow = List.generate(9, (index) => index + 1); // 1-9
    } else if (currentPage == 1) {
      inningsToShow = List.generate(9, (index) => index + 10); // 10-18
    } else {
      inningsToShow = List.generate(9, (index) => index + 19); // 19-27
    }

    return Column(
      children: [
        // Prior to Game button for "Looks On" verb
        if (verbName == 'Looks On') ...[
          GestureDetector(
            onTap: () {
              setState(() {
                _isPriorToGame = !_isPriorToGame;
                if (_isPriorToGame) {
                  _selectedRbiInning = null;
                }
                _selectedVerb = verbName;
                _selectedActionVerb = verbName;
              });
              setDialogState(() {});
              _updateCaption();
            },
            child: Container(
              width: double.infinity,
              height: 33,
              margin: const EdgeInsets.only(bottom: 8),
              alignment: Alignment.center,
              decoration: BoxDecoration(
                color:
                    _isPriorToGame ? Colors.grey.shade300 : Colors.grey.shade50,
                borderRadius: BorderRadius.circular(3),
                border: Border.all(color: Colors.grey.shade300, width: 0.5),
              ),
              child: Text(
                'Prior to Game',
                style: TextStyle(
                  fontSize: 10,
                  fontWeight: FontWeight.w500,
                  color: _isPriorToGame ? Colors.white : Colors.grey.shade700,
                ),
              ),
            ),
          ),
        ],
        // Inning buttons in 3 rows with 4th column for plus/minus
        ...List.generate(3, (rowIndex) {
          return Padding(
            padding: const EdgeInsets.only(bottom: 4),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                // First 3 columns: inning buttons
                ...List.generate(3, (colIndex) {
                  final inningIndex = (rowIndex * 3) + colIndex;
                  if (inningIndex >= inningsToShow.length) {
                    return const SizedBox(width: 36, height: 33); // Empty space
                  }
                  final inning = inningsToShow[inningIndex];
                  final isSelected = _selectedRbiInning == inning;
                  return GestureDetector(
                    onTap: () {
                      setState(() {
                        _selectedRbiInning =
                            _selectedRbiInning == inning ? null : inning;
                        if (_selectedRbiInning != null) {
                          _isPriorToGame = false;
                          _selectedVerb = verbName;
                          _selectedActionVerb = verbName;
                        }
                      });
                      setDialogState(() {});
                      _updateCaption();
                    },
                    child: Container(
                      width: 36,
                      height: 33,
                      margin: const EdgeInsets.symmetric(horizontal: 2),
                      alignment: Alignment.center,
                      decoration: BoxDecoration(
                        color: isSelected
                            ? Colors.grey.shade300
                            : Colors.grey.shade50,
                        borderRadius: BorderRadius.circular(3),
                        border:
                            Border.all(color: Colors.grey.shade300, width: 0.5),
                      ),
                      child: Text(
                        '$inning',
                        style: TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w500,
                          color:
                              isSelected ? Colors.white : Colors.grey.shade700,
                        ),
                      ),
                    ),
                  );
                }),
              ],
            ),
          );
        }),
        // Navigation buttons row
        const SizedBox(height: 4),
        Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            // Minus button
            GestureDetector(
              onTap: currentPage > 0
                  ? () {
                      setState(() {
                        _extraInningsPage--;
                        if (_extraInningsPage == 0) {
                          _showExtraInnings = false;
                        }
                        _selectedRbiInning = null;
                        _isPriorToGame = false;
                      });
                      setDialogState(() {});
                      _updateCaption();
                    }
                  : null,
              child: Container(
                width: 36,
                height: 33,
                margin: const EdgeInsets.symmetric(horizontal: 2),
                alignment: Alignment.center,
                decoration: BoxDecoration(
                  color: currentPage > 0
                      ? Colors.grey.shade50
                      : Colors.grey.shade200,
                  borderRadius: BorderRadius.circular(3),
                  border: Border.all(color: Colors.grey.shade300),
                ),
                child: Text(
                  '-',
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    color: currentPage > 0
                        ? Colors.grey.shade700
                        : Colors.grey.shade400,
                  ),
                ),
              ),
            ),
            // Plus button
            GestureDetector(
              onTap: currentPage < 2
                  ? () {
                      setState(() {
                        _extraInningsPage++;
                        _showExtraInnings = true;
                        _selectedRbiInning = null;
                        _isPriorToGame = false;
                      });
                      setDialogState(() {});
                      _updateCaption();
                    }
                  : null,
              child: Container(
                width: 36,
                height: 33,
                margin: const EdgeInsets.symmetric(horizontal: 2),
                alignment: Alignment.center,
                decoration: BoxDecoration(
                  color: currentPage < 2
                      ? Colors.grey.shade50
                      : Colors.grey.shade200,
                  borderRadius: BorderRadius.circular(3),
                  border: Border.all(color: Colors.grey.shade300),
                ),
                child: Text(
                  '+',
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.w500,
                    color: currentPage < 2
                        ? Colors.grey.shade700
                        : Colors.grey.shade400,
                  ),
                ),
              ),
            ),
          ],
        ),
      ],
    );
  }

  void _showSimpleVerbPopup(Offset position, String verbName) {
    showDialog(
      context: context,
      barrierColor: Colors.transparent,
      builder: (context) {
        return StatefulBuilder(
          builder: (context, setDialogState) {
            // Calculate dialog dimensions
            const double dialogWidth = 300;
            const double dialogHeight = 150;

            // Get screen dimensions
            final screenWidth = MediaQuery.of(context).size.width;
            final screenHeight = MediaQuery.of(context).size.height;

            // Center the dialog on the click position
            double left = position.dx - (dialogWidth / 2);
            double top = position.dy - (dialogHeight / 2);

            // Ensure dialog stays within screen bounds
            if (left < 10) left = 10;
            if (left + dialogWidth > screenWidth - 10)
              left = screenWidth - dialogWidth - 10;
            if (top < 10) top = 10;
            if (top + dialogHeight > screenHeight - 10)
              top = screenHeight - dialogHeight - 10;

            return Stack(
              children: [
                // Full screen GestureDetector to close on tap outside
                Positioned.fill(
                  child: GestureDetector(
                    onTap: () {
                      Navigator.pop(context);
                    },
                    child: Container(color: Colors.transparent),
                  ),
                ),
                // Position the dialog centered on the click location
                Positioned(
                  left: left,
                  top: top,
                  child: Material(
                    elevation: 8,
                    borderRadius: BorderRadius.circular(4),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        // Title
                        Container(
                          width: dialogWidth,
                          padding: const EdgeInsets.all(12),
                          decoration: BoxDecoration(
                            color: Colors.grey.shade100,
                            borderRadius: const BorderRadius.only(
                              topLeft: Radius.circular(4),
                              topRight: Radius.circular(4),
                            ),
                          ),
                          child: Row(
                            mainAxisAlignment: MainAxisAlignment.spaceBetween,
                            children: [
                              Text(
                                verbName,
                                style: TextStyle(
                                  fontSize: 10,
                                  fontWeight: FontWeight.w600,
                                  color: Colors.grey.shade800,
                                ),
                              ),
                              InkWell(
                                onTap: () {
                                  Navigator.pop(context);
                                },
                                borderRadius: BorderRadius.circular(4),
                                child: Container(
                                  width: 20,
                                  height: 20,
                                  alignment: Alignment.center,
                                  child: Icon(
                                    Icons.close,
                                    size: 14,
                                    color: Colors.grey.shade700,
                                  ),
                                ),
                              ),
                            ],
                          ),
                        ),
                        // Content
                        Container(
                          padding: const EdgeInsets.all(12),
                          width: dialogWidth,
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              SizedBox(
                                width: double.infinity,
                                height: 40,
                                child: ElevatedButton(
                                  onPressed: () async {
                                    // Set verb so chip stays highlighted and caption updates
                                    setState(() {
                                      _selectedVerb = verbName;
                                      _selectedActionVerb = verbName;
                                    });
                                    _mergeVerbKeywordsIntoFieldIfEnabled(
                                        verbName);
                                    _updateCaption();
                                    // Save IPTC metadata
                                    if (widget.onSaveIptc != null) {
                                      await widget.onSaveIptc!();
                                    }
                                    // Close the popup
                                    Navigator.pop(context);
                                    // Move to next image
                                    if (widget.onNextImage != null) {
                                      widget.onNextImage!();
                                    }
                                  },
                                  style: ElevatedButton.styleFrom(
                                    foregroundColor: Colors.grey.shade700,
                                    padding: const EdgeInsets.symmetric(
                                        horizontal: 8, vertical: 8),
                                    shape: RoundedRectangleBorder(
                                      borderRadius: BorderRadius.circular(4),
                                    ),
                                  ),
                                  child: Row(
                                    mainAxisSize: MainAxisSize.min,
                                    children: const [
                                      Text('Save',
                                          style: TextStyle(fontSize: 10)),
                                      SizedBox(width: 4),
                                      Icon(Icons.arrow_forward, size: 14),
                                    ],
                                  ),
                                ),
                              ),
                              const SizedBox(height: 8),
                              SizedBox(
                                width: double.infinity,
                                height: 40,
                                child: ElevatedButton(
                                  onPressed: _disableFtp ? null : _onFtpPressed,
                                  style: ElevatedButton.styleFrom(
                                    backgroundColor: _disableFtp
                                        ? Colors.grey.shade300
                                        : const Color(0xFF0052CC),
                                    foregroundColor: _disableFtp
                                        ? Colors.grey.shade600
                                        : Colors.white,
                                    padding: const EdgeInsets.symmetric(
                                        horizontal: 12, vertical: 8),
                                    shape: RoundedRectangleBorder(
                                      borderRadius: BorderRadius.circular(4),
                                    ),
                                    alignment: Alignment.centerLeft,
                                  ),
                                  child: Row(
                                    mainAxisAlignment: MainAxisAlignment.center,
                                    children: [
                                      SvgPicture.asset(
                                        'assets/images/rocket_icon_white_only.svg',
                                        width: 16,
                                        height: 16,
                                        fit: BoxFit.contain,
                                        colorFilter: ColorFilter.mode(
                                          _disableFtp
                                              ? Colors.grey.shade600
                                              : Colors.white,
                                          BlendMode.srcIn,
                                        ),
                                      ),
                                      const SizedBox(width: 4),
                                      Text(
                                        _currentFtpProfile != null
                                            ? 'FTP ($_currentFtpProfile)'
