  Widget _buildMainVerbSelector() {
    final sport = widget.sport?.toLowerCase() ?? 'baseball';
    final String thirdCategory = sport == 'hockey' ? 'Goalie' : 'Running';
    print(
        'DEBUG _buildMainVerbSelector: sport=$sport, thirdCategory=$thirdCategory');

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const Text(
          'Main Action:',
          style: TextStyle(fontSize: 11, fontWeight: FontWeight.w600),
        ),
        const SizedBox(height: 2),
        LayoutBuilder(
          builder: (context, constraints) {
            double chipWidth =
                (constraints.maxWidth - 4) / 3; // 3 columns with 2px spacing
            return SizedBox(
              height: 60, // Fixed height for 2 rows
              child: Stack(
                children: [
                  // Row 1
                  Positioned(
                    top: 0,
                    left: 0,
                    width: chipWidth,
                    height: 28,
                    child: _buildVerbChip('Offense', 'Offense'),
                  ),
                  Positioned(
                    top: 0,
                    left: chipWidth + 2,
                    width: chipWidth,
                    height: 28,
                    child: _buildVerbChip('Defense', 'Defense'),
                  ),
                  Positioned(
                    top: 0,
                    left: (chipWidth + 2) * 2,
                    width: chipWidth -
                        0.5, // Slightly narrower to prevent overflow
                    height: 28,
                    child: _buildVerbChip(thirdCategory, thirdCategory),
                  ),
                  // Row 2
                  Positioned(
                    top: 30,
                    left: 0,
                    width: chipWidth,
                    height: 28,
                    child: _buildVerbChip('Reactions', 'Reactions'),
                  ),
                  Positioned(
                    top: 30,
                    left: chipWidth + 2,
                    width: chipWidth,
                    height: 28,
                    child: _buildVerbChip('Non Game-Action', 'Non Game'),
                  ),
                ],
              ),
            );
          },
        ),
      ],
    );
  }

  Widget _buildVerbChip(String verb, String label) {
    // Highlight when this category is selected, or when any verb in this category is selected
    final isSelected = _selectedVerb == verb ||
        (verbCategories[verb]?.contains(_selectedVerb ?? '') ?? false);
    return GestureDetector(
      onTap: () {
        setState(() {
          if (isSelected) {
            _selectedVerb = null;
            _selectedActionVerb = null; // Clear action verb when deselecting
            _selectedHomeRunType = null;
            _selectedTagsAction = null; // Clear tags action when deselecting
            _selectedBase = null; // Clear selected base when deselecting
            _rbiCount = null;
            _selectedRbiInning = null;
            _isBatterRunning = false;
          } else {
            _selectedVerb = verb;
            _selectedActionVerb = verb; // Store for caption generation
            // Reset other states when selecting a new verb
            _selectedHomeRunType = null;
            _rbiCount = null;
            _selectedRbiInning = null;
            _isBatterRunning = false;
          }
          _updateCaption();
        });
      },
      child: Container(
        alignment: Alignment.center,
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 6),
        decoration: BoxDecoration(
          color: isSelected ? Colors.blue.shade100 : Colors.grey.shade100,
          borderRadius: BorderRadius.circular(12),
          border: Border.all(
            color: isSelected ? Colors.blue.shade300 : Colors.grey.shade300,
          ),
        ),
        child: Text(
          label,
          textAlign: TextAlign.center,
          maxLines: 1,
          overflow: TextOverflow.ellipsis,
          style: TextStyle(
            fontSize: 14,
            fontWeight: FontWeight.w500,
            color: isSelected ? Colors.blue.shade700 : Colors.grey.shade700,
          ),
        ),
      ),
    );
  }

  Widget _buildHomeRunOptions() {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
