  void _showInningSelector() {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Select Inning'),
        content: SizedBox(
          width: 300,
          height: 400,
          child: GridView.builder(
            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: 3,
              childAspectRatio: 2,
              crossAxisSpacing: 8,
              mainAxisSpacing: 8,
            ),
            itemCount: 12, // 1-9 + 10, 11, 12
            itemBuilder: (context, index) {
              final inning = index < 9 ? index + 1 : index + 1;
              final isSelected = _selectedRbiInning == inning;
              return GestureDetector(
                onTap: () {
                  setState(() {
                    _selectedRbiInning = inning;
                  });
                  _updateCaption();
                  Navigator.pop(context);
                },
                child: Container(
                  decoration: BoxDecoration(
                    color: isSelected
                        ? Colors.blue.shade100
                        : Colors.grey.shade200,
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: isSelected
                          ? Colors.blue.shade300
                          : Colors.grey.shade400,
                    ),
                  ),
                  child: Center(
                    child: Text(
                      _getOrdinalSuffix(inning),
                      style: TextStyle(
                        fontSize: 12,
                        fontWeight:
                            isSelected ? FontWeight.w600 : FontWeight.normal,
                        color: isSelected
                            ? Colors.blue.shade700
                            : Colors.grey.shade600,
                      ),
                    ),
                  ),
                ),
              );
            },
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text('Cancel'),
          ),
        ],
      ),
    );
  }

  Widget _buildPeriodButton(String period, [Function? dialogSetState]) {
    final isSelected = _selectedPeriod == period;
    return MouseRegion(
      cursor: SystemMouseCursors.click,
      child: GestureDetector(
        onTap: () {
          setState(() {
            _selectedPeriod = _selectedPeriod == period ? null : period;
            if (_selectedPeriod != null) {
              _isPriorToGame = false;
            }
            // Set the action verb for caption generation
            if (_pendingVerbSelection != null) {
              _selectedActionVerb = _pendingVerbSelection;
              _selectedHomeRunType = null;
              _rbiCount = null;
            }
          });
          if (dialogSetState != null) {
            dialogSetState(() {});
          }
          _updateCaption();
        },
        child: Container(
          width: 36,
          height: 33,
          alignment: Alignment.center,
          decoration: BoxDecoration(
            color: isSelected ? Colors.grey.shade400 : Colors.grey.shade50,
            borderRadius: BorderRadius.circular(3),
            border: Border.all(
              color: Colors.grey.shade300,
              width: 0.5,
            ),
          ),
          child: Text(
            period,
            style: TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w500,
              color: isSelected ? Colors.white : Colors.grey.shade700,
            ),
          ),
        ),
      ),
    );
  }

