    debugInfo += 'Players WITH jersey numbers: $playersWithNumbers\n';
    debugInfo += 'Players WITHOUT jersey numbers: $playersWithoutNumbers\n';
    debugInfo += 'Total players: ${roster.length}\n';

    // Show popup
