  Future<void> _updateCaption() async {
    // Safety check: if either team is not selected, don't try to generate captions
    if (selectedHomeTeam == null || selectedAwayTeam == null) {
      captionController.clear();
      _keyboardFireCaptionNotifier.value = '';
      return;
    }

    // Get photo date from metadata, fallback to current date
    DateTime photoDate = DateTime.now();
    if (widget.metadata != null) {
      final dateTimeOriginal = widget.metadata!['DateTimeOriginal']?.toString();
      final createDate = widget.metadata!['CreateDate']?.toString();
      final modifyDate = widget.metadata!['ModifyDate']?.toString();

      // Try to parse the date from EXIF data
      final dateString = dateTimeOriginal ?? createDate ?? modifyDate;
      if (dateString != null && dateString.isNotEmpty) {
        try {
          // Parse EXIF date format (YYYY:MM:DD HH:MM:SS)
          final parts = dateString.split(' ');
          if (parts.isNotEmpty) {
            final datePart = parts[0];
            final dateComponents = datePart.split(':');
            if (dateComponents.length >= 3) {
              final year = int.parse(dateComponents[0]);
              final month = int.parse(dateComponents[1]);
              final day = int.parse(dateComponents[2]);
              photoDate = DateTime(year, month, day);
            }
          }
        } catch (e) {
          print('Error parsing photo date: $e');
          // Fallback to current date
        }
      } else {}
    } else {}

    // Get date components
    final city = cityController.text;
    final prov = provinceController.text;
    final monLC = _month(photoDate.month);
    final day = photoDate.day;
    final year = photoDate.year;
    final monthUpper = monLC.toUpperCase();
    final formattedDate = '$monLC $day, $year';
    final dateline = _formatDateline(city, prov, monthUpper, day);
    final locationSuffix = _formatLocationSuffix(city, prov, formattedDate);

    // Determine which team the selected players belong to
    // First player selected = Main focus, opposite team players = always "against"
    Set<String> activePlayers;
    Set<String> opponentPlayers;
    String? opponentTeamName;

    if (selectedAwayPlayers.isNotEmpty && selectedHomePlayers.isEmpty) {
      // Only away team players are selected
      activePlayers = selectedAwayPlayers;
      opponentPlayers = <String>{};
      opponentTeamName = selectedHomeTeam;
    } else if (selectedHomePlayers.isNotEmpty && selectedAwayPlayers.isEmpty) {
      // Only home team players are selected
      activePlayers = selectedHomePlayers;
      opponentPlayers = <String>{};
      opponentTeamName = selectedAwayTeam;
    } else if (selectedHomePlayers.isNotEmpty &&
        selectedAwayPlayers.isNotEmpty) {
      // Both teams have players - use the first team selected as main focus

      if (_firstTeamSelected == true) {
        // Home team was selected first, so they're the main focus

        activePlayers = selectedHomePlayers;
        opponentPlayers = selectedAwayPlayers;
        opponentTeamName = selectedAwayTeam;
      } else if (_firstTeamSelected == false) {
        // Away team was selected first, so they're the main focus

        activePlayers = selectedAwayPlayers;
        opponentPlayers = selectedHomePlayers;
        opponentTeamName = selectedHomeTeam;
      } else {
        // Fallback: if _firstTeamSelected is null, use home team as default

        activePlayers = selectedHomePlayers;
        opponentPlayers = selectedAwayPlayers;
        opponentTeamName = selectedAwayTeam;
      }
    } else {
      // No players selected
      captionController.clear();
      _keyboardFireCaptionNotifier.value = '';
      _updatePersonalityField(); // Clear personality field when no players selected
      return;
    }

    if (activePlayers.isEmpty) {
      captionController.clear();
      _keyboardFireCaptionNotifier.value = '';
      return;
    }

    // Get the verb to use for player formatting
    final verbToUse = _selectedActionVerb ?? _selectedVerb;

    // Format the main player(s)
    String playerName;

    if ((_selectedHittingAction == 'celebrates' ||
            _selectedHittingAction == 'celebrates_in_dugout' ||
            verbToUse == 'Celebration' ||
            verbToUse == 'Celebrates' ||
            verbToUse == 'Celebrates a Goal' ||
            verbToUse == 'Celebrates With' ||
            verbToUse == 'Celebrates Against') &&
        _firstPlayerSelected != null) {
      // For celebration actions, check if "with teammates" is selected OR if we're in a hit interface OR celebration interface with multiple players
      final isHitInterface = (verbToUse == 'Single' ||
          verbToUse == 'Double' ||
          verbToUse == 'Triple' ||
          verbToUse == 'Home Run' ||
          verbToUse == 'Grand Slam');
      final isCelebrationInterface = (verbToUse == 'Celebration' ||
          verbToUse == 'Celebrates' ||
          verbToUse == 'Celebrates a Goal' ||
          verbToUse == 'Celebrates With' ||
          verbToUse == 'Celebrates Against');
      final hasMultiplePlayers = activePlayers.length > 1;

      // print(
      //     'DEBUG: _isCelebratingWithTeammates = $_isCelebratingWithTeammates');
      // print(
      //     'DEBUG: isHitInterface = $isHitInterface, isCelebrationInterface = $isCelebrationInterface, hasMultiplePlayers = $hasMultiplePlayers');

      if (_isCelebratingWithTeammates ||
          (isHitInterface && hasMultiplePlayers) ||
          (isCelebrationInterface && hasMultiplePlayers)) {
        // If "with teammates" is selected OR we're in a hit interface with multiple players, only use the main player
        // Determine which team the main player is from using normalized comparison (same logic as _getTeammates)
        final isMainPlayerHome = selectedHomePlayers.any(
          (player) =>
              _removeJerseyNumberFromName(player) == _firstPlayerSelected,
        );
        final mainPlayerTeam =
            isMainPlayerHome ? selectedHomeTeam : selectedAwayTeam;

        // Get the full display name (with jersey number) for the first player
        final mainPlayerFullName = isMainPlayerHome
            ? selectedHomePlayers.firstWhere(
                (player) =>
                    _removeJerseyNumberFromName(player) == _firstPlayerSelected,
                orElse: () => _firstPlayerSelected!,
              )
            : selectedAwayPlayers.firstWhere(
                (player) =>
                    _removeJerseyNumberFromName(player) == _firstPlayerSelected,
                orElse: () => _firstPlayerSelected!,
              );

        playerName = '$mainPlayerFullName of the $mainPlayerTeam';
      } else {
        // If "with teammates" is NOT selected and not a multi-player hit interface, use all active players
        playerName = _combinePlayersWithSingleTeam(activePlayers.toList());
      }
    } else {
      // For Pitching Change, don't set playerName since it's handled in actionPhrase
      if (verbToUse == 'Pitching Change') {
        playerName = '';
      } else {
        // For other actions, use all active players
        playerName = _combinePlayersWithSingleTeam(activePlayers.toList());
      }
    }

    // Build the action phrase based on selected verb
    String actionPhrase = '';

    final verbForAction = _selectedActionVerb ?? _selectedVerb;
    if (verbForAction != null) {
      actionPhrase = _buildActionPhrase();
    }

    // Handle opponent players if selected
    String opponentPart = '';
    // Hockey verbs that always embed the opponent (with or without "against") in
    // their own action phrase via _buildActionPhrase(). We suppress opponentPart
    // for all of them so the opponent name is never appended twice — even when the
    // user has set omitAgainst=true (which removes "against" from the phrase but
    // still includes the player name, causing the old contains('against') check to
    // miss and double-append).
    const Set<String> hockeyOpponentVerbs = {
      // Hockey
      'Shoots', 'Scores', 'Skates', 'Goes to the Net', 'Battles', 'Faceoff',
      'Checks', 'Defends', 'Blocks', 'Clears', 'Guards the Net', 'Saves',
      'Passes', 'Power Play', 'Breakaway',
      // Basketball (all embed opponent in their action phrase)
      'Drives', 'Dribbles', 'Dunks', 'Lays Up',
      'Three-Pointer', 'Free Throw', 'Steals the Ball', 'Contests', 'Rebounds',
      'Takes the Court',
    };
    if (actionPhrase.contains('against') ||
        hockeyOpponentVerbs.contains(verbToUse) ||
        _selectedHittingAction == 'celebrates' ||
        _selectedHittingAction == 'celebrates_in_dugout' ||
        _selectedHittingAction == 'trots_the_bases' ||
        verbToUse == 'At Bat' ||
        verbToUse == 'Pitching' ||
        verbToUse == 'Swings' ||
        verbToUse == 'Fielding Position' ||
        verbToUse == 'Catches' ||
        verbToUse == 'Throws' ||
        verbToUse == 'Tags' ||
        verbToUse == 'Groundball' ||
        verbToUse == 'Steals' ||
        verbToUse == 'Slides' ||
        verbToUse == 'Runs' ||
        verbToUse == 'Rounds' ||
        verbToUse == 'Double Play' ||
        verbToUse == 'Triple Play' ||
        verbToUse == 'Celebration' ||
        verbToUse == 'Celebrates' ||
        verbToUse == 'Celebrates With' ||
        verbToUse == 'Celebrates Against' ||
        verbToUse == 'Walks' ||
        verbToUse == 'Dejection' ||
        verbToUse == 'Looks On' ||
        verbToUse == 'Walks Off Field' ||
        verbToUse == 'Runs Off Field' ||
        verbToUse == 'Takes the Field' ||
        verbToUse == 'Comes Off the Field' ||
        verbToUse == 'National Anthem' ||
        verbToUse == 'Post Game Win' ||
        verbToUse == 'Post Game Loss' ||
        verbToUse == 'Batting Practice' ||
        verbToUse == 'Fielding Practice' ||
        verbToUse == 'Warm Ups' ||
        verbToUse == 'Walks On Field' ||
        verbToUse == 'Runs On Field' ||
        verbToUse == 'Stretching' ||
        verbToUse == 'Pitching Change' ||
        customCelebrationController.text.isNotEmpty ||
        customDejectionController.text.isNotEmpty) {
      // For these actions, don't add opponent part here - it's handled in the action phrase
      opponentPart = '';
    } else {
      // For other actions, include specific players if selected
      if (opponentPlayers.isNotEmpty) {
        final opponentNames = _combinePlayersWithSingleTeam(
          opponentPlayers.toList(),
        );
        opponentPart = ' against $opponentNames';
      } else if (opponentTeamName != null) {
        opponentPart = ' against the $opponentTeamName';
      }
    }

    // Add inning/period if specified (but not for post-game verbs or Pitching Change)
    String inningPart = '';
    final isPostGameVerb =
        _selectedVerb == 'Post Game Win' || _selectedVerb == 'Post Game Loss';
    final isPitchingChange = _selectedVerb == 'Pitching Change';

    if (!isPostGameVerb && !isPitchingChange) {
      if (widget.sport?.toLowerCase() == 'hockey') {
        // Hockey mode: use periods
        if (_selectedPeriod != null) {
          inningPart = _getHockeyPeriodText(_selectedPeriod!);
        } else if (_isPriorToGame) {
          inningPart = ' prior to the game';
        }
      } else if (widget.sport?.toLowerCase() == 'basketball') {
        // Basketball mode: use quarters
        if (_selectedPeriod != null) {
          inningPart = _getBasketballQuarterText(_selectedPeriod!);
        } else if (_isPriorToGame) {
          inningPart = ' prior to the game';
        }
      } else {
        // Baseball mode: use innings
        if (_selectedRbiInning != null) {
          inningPart =
              ' during the ${_getOrdinalSuffix(_selectedRbiInning!)} inning';
        } else if (_isPriorToGame) {
          inningPart = ' prior to the game';
        }
      }
      // Note: _isPriorToGame is handled separately in the gamePart logic
    }

    // Use home team stadium from API, fallback to controller if not available
    final stadium = homeTeamStadium ?? stadiumController.text;
    // Get creator and credit – prefer in-session byline overrides first.
    String? creatorValue = _bylinePhotographerOverride;
    String? creditValue = _bylineCreditOverride;

    // Only fetch from image / metadata when at least one field is not overridden.
    if (creatorValue == null || creditValue == null) {
      // Load Creator and Credit directly from the current image file
      if (widget.currentImagePath != null &&
          widget.currentImagePath!.isNotEmpty) {
        final values =
            await _loadCreatorAndCreditFromImage(widget.currentImagePath!);
        creatorValue ??= values['creator'];
        creditValue ??= values['credit'];
        print(
            'DEBUG: Loaded from image file - Creator: "$creatorValue", Credit: "$creditValue"');
      } else {
        // Fall back to metadata if no image path
        creatorValue ??= widget.metadata?['IPTC:By-line']?.toString() ??
            widget.metadata?['By-line']?.toString() ??
            widget.metadata?['Creator']?.toString() ??
            widget.metadata?['XMP:Creator']?.toString();
        creditValue ??= widget.metadata?['IPTC:Credit']?.toString() ??
            widget.metadata?['Credit']?.toString();
        print(
            'DEBUG: No image path, using metadata - Creator: "$creatorValue", Credit: "$creditValue"');
      }
    }

    // Debug logging

    String photoBy;
    // Since we're now getting String values from the metadata widget, we don't need List handling
    photoBy = creatorValue ?? '';

    // Try to detect photographer from camera serial number if no creator is set and serial number bylines are enabled
    if (photoBy.isEmpty &&
        widget.cameraService != null &&
        widget.metadata != null) {
      // Check if serial number bylines are enabled
      try {
        final preferencesService = await PreferencesService.getInstance();
        final serialNumberBylinesEnabled =
            await preferencesService.getSerialNumberBylines();

        if (serialNumberBylinesEnabled) {
          final serialNumber = widget.metadata!['SerialNumber']?.toString();
          if (serialNumber != null && serialNumber.isNotEmpty) {
            if (widget.cameraService!.isSerialNumberUnknown(serialNumber)) {
              // Show dialog for unknown serial number
              await _showUnknownSerialDialog(serialNumber);
              // Try to detect again after potential assignment
              final detectedPhotographer = widget.cameraService!
                  .detectPhotographerFromExif(widget.metadata!);
              if (detectedPhotographer != null) {
                photoBy = detectedPhotographer;
                print(
                    'DEBUG: Auto-detected photographer from camera serial after assignment: $photoBy');
              }
            } else {
              final detectedPhotographer = widget.cameraService!
                  .detectPhotographerFromExif(widget.metadata!);
              if (detectedPhotographer != null) {
                photoBy = detectedPhotographer;
                print(
                    'DEBUG: Auto-detected photographer from camera serial: $photoBy');
              }
            }
          }
        } else {
          print(
              'DEBUG: Serial number bylines disabled, skipping auto-detection');
        }
      } catch (e) {
        print('DEBUG: Error checking serial number bylines preference: $e');
      }
    }

    // Build the byline using EXIF Creator/Credit data
    String byline;
    if (photoBy.isNotEmpty &&
        creditValue != null &&
        creditValue.toString().isNotEmpty) {
      byline = _bylineUseSlash
          ? '$photoBy/$creditValue'
          : '$photoBy $creditValue';
    } else if (photoBy.isNotEmpty) {
      byline = photoBy;
    } else if (creditValue != null && creditValue.toString().isNotEmpty) {
      byline = creditValue.toString();
    } else {
      byline = ''; // No creator/credit info available
    }

    // Add custom text between players if provided (but not magic input)
    String customTextPart = '';
    // Magic bar removed: no custom text part from magic bar
    if (false) {
      customTextPart = '';
    }

    // Build the final caption
    String gamePart;
    String opponentPartModified;

    // Set game part based on sport
    final sport = widget.sport?.toLowerCase() ?? 'baseball';
    if (sport == 'hockey') {
      gamePart = 'in their NHL game';
    } else if (sport == 'basketball') {
      gamePart = 'in their NBA game';
    } else {
      gamePart = 'in their MLB game';
    }

    if (_isPriorToGame || _isPostGame) {
      // For pre-game or post-game, we need to extract just the team name from opponentPart
      String teamName = '';
      if (opponentPart.contains('against the ')) {
        teamName = opponentPart.replaceAll(' against the ', '');
      } else if (opponentPart.contains('against ')) {
        teamName = opponentPart.replaceAll(' against ', '');
      }

      // If teamName is empty, try to get it from the opponent team
      if (teamName.isEmpty && opponentTeamName != null) {
        teamName = opponentTeamName;
      }

      // Check if action phrase already contains "against" or "playing" to avoid duplication
      if (actionPhrase.contains('against') ||
          actionPhrase.contains('playing')) {
        opponentPartModified =
            ''; // Don't add opponent info if already in action phrase
      } else if (_isPriorToGame) {
        opponentPartModified = ' ahead of playing against the $teamName';
      } else {
        // _isPostGame
        opponentPartModified = ' after playing against the $teamName';
      }
    } else {
      opponentPartModified = opponentPart;
    }

    // Determine if we should skip inning/period part
    final skipInningPart = _isPriorToGame || _isPostGame;

    // Getty Images disclaimer: inserted when the credit field contains "Getty Images"
    const _gettyDisclaimer =
        'NOTE TO USER: User expressly acknowledges and agrees that, by downloading '
        'and/or using this Photograph, user is consenting to the terms and conditions '
        'of the Getty Images License Agreement.';
    final isGetty =
        byline.toLowerCase().contains('getty images') && sport == 'basketball';
    final disclaimerPart = isGetty ? ' $_gettyDisclaimer' : '';

    String bylineSuffix = '';
    if (byline.isNotEmpty) {
      final prefix = _bylinePrefixText.trim();
      final body = prefix.isNotEmpty ? '$prefix $byline' : byline;
      bylineSuffix = _bylineUseBrackets ? ' ($body)' : ' $body';
    }
    var caption = '$dateline '
        '$playerName$customTextPart${actionPhrase.isNotEmpty ? ' $actionPhrase' : ''}$opponentPartModified${skipInningPart ? '' : inningPart} '
        '$gamePart at $stadium on $formattedDate $locationSuffix.$disclaimerPart$bylineSuffix';

    // Apply diacritic removal if checkbox is checked
    if (_removeAccent) {
      caption = _removeDiacritics(caption);
    }

    captionController.text = caption;
    _keyboardFireCaptionNotifier.value = caption;

    // Update personality field with all selected players (always call to handle empty case)
    _updatePersonalityField();
  }

  /// Called by external widgets (e.g. KeyboardFireDialog) to open the byline editor.
  void openBylineEditor() => _showBylineEditorDialog();

  /// Whether a byline override is currently active (for indicator display).
  bool get hasBylineOverride =>
      _bylinePhotographerOverride != null || _bylineCreditOverride != null;

  // Public method to select a player and verb from external widgets (like PlayerPopupCaptionBoard)
  void selectPlayerAndVerb(Player player, String verb, bool isHome) {
    setState(() {
      // Clear existing selections
      selectedHomePlayers.clear();
      selectedAwayPlayers.clear();
      _popupCustomVerb = null;

      // Select the player
      final playerDisplayName = player.displayName ?? player.fullName;
      if (isHome) {
        selectedHomePlayers.add(playerDisplayName);
      } else {
        selectedAwayPlayers.add(playerDisplayName);
      }

      // Set the verb
      _selectedVerb = verb;
      _selectedActionVerb = verb;

      // Check if this is a "prior to game" verb
      final priorToGameVerbs = [
        'Warm Ups',
        'Takes the Ice',
        'National Anthem',
        'Stretching',
        'Batting Practice',
        'Fielding Practice',
        'Takes the Field',
      ];

      if (priorToGameVerbs.contains(verb)) {
        _isPriorToGame = true;
        _selectedPeriod = null; // Clear period selection for prior to game
        _selectedRbiInning = null; // Clear inning selection for prior to game
      } else {
        _isPriorToGame = false;
      }
    });

    // Trigger caption generation
    _mergeVerbKeywordsIntoFieldIfEnabled(verb);
    _updateCaption();
  }

  // Public method to update selected players from PlayerPopupCaptionBoard without choosing a verb
  Future<void> updatePlayersFromPopup(
    Set<Player> homePlayers,
    Set<Player> awayPlayers,
    Player? firstPlayer,
    bool? firstIsHome,
  ) async {
    setState(() {
      selectedHomePlayers
        ..clear()
        ..addAll(
            homePlayers.map((player) => player.displayName ?? player.fullName));
      selectedAwayPlayers
        ..clear()
        ..addAll(
            awayPlayers.map((player) => player.displayName ?? player.fullName));

      if (firstPlayer != null) {
        final displayName = firstPlayer.displayName ?? firstPlayer.fullName;
        _firstPlayerSelected = _removeJerseyNumberFromName(displayName);
        _firstTeamSelected = firstIsHome;
      } else {
        _firstPlayerSelected = null;
        _firstTeamSelected = null;
      }

      // Clear custom verb when all players are cleared (after save)
      if (homePlayers.isEmpty && awayPlayers.isEmpty) {
        _popupCustomVerb = null;
      }
    });

    if (homePlayers.isNotEmpty || awayPlayers.isNotEmpty) {
      await _reEvaluateCustomVerbPhrase();
      _updateCaption();
      _reapplyVerbKeywordsIfEnabled();
    } else {
      // Revert to original caption/personality for this image.
      captionController.text = _originalCaptionFromMetadata ?? '';
      personalityController.text = _originalPersonalityFromMetadata ?? '';
    }
  }

  // Public method to update the hockey period from the PlayerPopupCaptionBoard
  // This keeps the selected period persistent across images and applies it
  // to the caption whenever players are selected.
  // Pass null to deselect the period.
  void updatePeriodFromPopup(String? period) {
    setState(() {
      _selectedPeriod = period;
      final isBaseball = widget.sport?.toLowerCase() == 'baseball';
      if (isBaseball &&
          (period == 'Pre-Game' || period == 'Post Game' || period == null)) {
        _selectedRbiInning = null;
      }
      if (period == 'Pre-Game') {
        // Pre-Game uses special "ahead of playing against" caption format
        _isPriorToGame = true;
        _isPostGame = false;
      } else if (period == 'Post Game') {
        // Post Game uses special "after playing against" caption format
        _isPriorToGame = false;
        _isPostGame = true;
      } else if (period != null) {
        _isPriorToGame = false;
        _isPostGame = false;
      } else {
        _isPriorToGame = false;
        _isPostGame = false;
      }
    });

    // If there are already players selected, immediately rebuild the caption
    // so the chosen period appears in the text (or is removed if period is null).
    if (selectedHomePlayers.isNotEmpty || selectedAwayPlayers.isNotEmpty) {
      _updateCaption();
    }
  }

  /// Baseball inning from the player popup / Keyboard Fire (1–27 in main UI).
  void updateInningFromPopup(int? inning) {
    setState(() {
      _selectedRbiInning = inning;
      _selectedPeriod = null;
      if (inning != null) {
        _isPriorToGame = false;
        _isPostGame = false;
      }
    });
    if (selectedHomePlayers.isNotEmpty || selectedAwayPlayers.isNotEmpty) {
      _updateCaption();
    }
  }

  /// Current hockey period selection (for Keyboard Fire panel / popup).
  String? get selectedPeriod => _selectedPeriod;

  /// Current baseball inning selection (for Keyboard Fire panel).
  int? get selectedRbiInning => _selectedRbiInning;

  // Getter for homeOnLeft to allow parent to access it
  bool get homeOnLeft => _homeOnLeft;

  // Update custom verb text live from player popup
  void switchTeams() {
    print('DEBUG: switchTeams called, _homeOnLeft was: $_homeOnLeft');
    setState(() {
      _homeOnLeft = !_homeOnLeft;
    });
    print('DEBUG: switchTeams completed, _homeOnLeft is now: $_homeOnLeft');
  }

  // Helper to re-evaluate custom verb plural phrase based on current player count
  Future<void> _reEvaluateCustomVerbPhrase() async {
    final verbText = _selectedActionVerb ?? _selectedVerb;
    if (verbText == null) return;

    // List of category verbs that don't use _popupCustomVerb
    final categoryVerbs = {
      'Skates',
      'Shoots',
      'Battles',
      'Scores',
      'Goes to the Net',
      'Faceoff',
      'Blocks',
      'Clears',
      'Checks',
      'Defends',
      'Saves',
      'Handles the Puck',
      'Stands in Net',
      'Guards the Net',
      'Power Play',
      'Breakaway',
      'Warm Ups',
      'Takes the Ice',
      'Walks to the Ice',
      'Comes Off the Ice',
      'National Anthem',
      'Stretching',
      'Bench',
      'Looks On',
      'Celebrates',
      'Celebrates a Goal',
      'Dejection',
      'Post Game Win',
      'Post Game Loss',
    };

    // Skip if it's a category verb (they don't use _popupCustomVerb)
    if (categoryVerbs.contains(verbText)) return;

    // Reload verb overrides to ensure we have the latest plural phrases
    _verbOverrides =
        await _preferencesService.getVerbOverrides(sport: _currentSport);

    // Get player count to determine if we should use plural phrase
    final activePlayerCount =
        selectedHomePlayers.length + selectedAwayPlayers.length;

    // Check if this is a custom verb
    final customVerbs =
        await _preferencesService.getCustomVerbs(sport: _currentSport);
    final customVerb = customVerbs.firstWhere(
      (v) => v['label'] == verbText,
      orElse: () => <String, dynamic>{},
    );

    setState(() {
      if (customVerb.isNotEmpty && customVerb.containsKey('verbPhrase')) {
        final verbPhrase = customVerb['verbPhrase'] as String? ?? verbText;
        final pluralPhrase = customVerb['pluralPhrase'] as String?;
        final usePluralPhrase = customVerb['usePluralPhrase'] as bool? ?? true;

        if (activePlayerCount > 1 &&
            usePluralPhrase &&
            pluralPhrase != null &&
            pluralPhrase.isNotEmpty) {
          _popupCustomVerb = pluralPhrase;
        } else {
          _popupCustomVerb = verbPhrase;
        }
      } else if (_verbOverrides.containsKey(verbText)) {
        // Check if this is a verb override
        final override = _verbOverrides[verbText]!;
        final singularPhrase = override['verbPhrase'] as String?;
        final pluralPhrase = override['pluralPhrase'] as String?;
        final usePluralPhrase = override['usePluralPhrase'] as bool? ?? true;

        if (activePlayerCount > 1 &&
            usePluralPhrase &&
            pluralPhrase != null &&
            pluralPhrase.isNotEmpty) {
          _popupCustomVerb = pluralPhrase;
        } else {
          _popupCustomVerb = singularPhrase ?? verbText;
        }
      }
    });
  }

  void updateCustomVerbFromPopup(String verbText) async {
    // Reload verb overrides to ensure we have the latest plural phrases
    _verbOverrides =
        await _preferencesService.getVerbOverrides(sport: _currentSport);

    if (verbText.isEmpty) {
      setState(() {
        _popupCustomVerb = null;
        _selectedVerb = null;
        _selectedActionVerb = null;
      });
      _updateCaption();
      return;
    }

    final resolvedVerb = _resolveCanonicalVerbKey(verbText.trim());

    // List of category verbs that need to go through the switch statement
    // to properly handle opposing players and other logic
    // This includes ALL verbs from player_popup_caption_board that have switch cases
    // that handle opposing players via _getOpposingPlayers()
    final categoryVerbs = {
      // Offense verbs
      'Skates',
      'Shoots',
      'Battles',
      'Scores',
      'Goes to the Net',
      'Faceoff',
      // Defense verbs
      'Blocks',
      'Clears',
      'Checks',
      'Defends',
      // Goalie verbs
      'Saves',
      'Handles the Puck',
      'Stands in Net',
      'Guards the Net',
      // Other verbs that handle opposing players
      'Power Play',
      'Breakaway',
      // Pre-game/Non-game verbs that have switch cases
      'Warm Ups',
      'Takes the Ice',
      'Walks to the Ice',
      'Comes Off the Ice',
      'National Anthem',
      'Stretching',
      'Bench',
      'Looks On',
      // Reaction verbs
      'Celebrates',
      'Celebrates a Goal',
      'Dejection',
      'Post Game Win',
      'Post Game Loss',
    };

    // If this is a category verb, don't set _popupCustomVerb so it goes through switch statement
    if (categoryVerbs.contains(resolvedVerb)) {
      setState(() {
        _popupCustomVerb = null;
        _selectedVerb = resolvedVerb;
        _selectedActionVerb = resolvedVerb;
      });
      _updateCaption();
      return;
    }

    // Check if this is a custom verb - look up its verbPhrase
    final customVerbs =
        await _preferencesService.getCustomVerbs(sport: _currentSport);
    final customVerb = customVerbs.firstWhere(
      (v) => v['label'] == resolvedVerb,
      orElse: () => <String, dynamic>{},
    );

    // Get player count to determine if we should use plural phrase
    final activePlayerCount =
        selectedHomePlayers.length + selectedAwayPlayers.length;

    setState(() {
      if (customVerb.isNotEmpty && customVerb.containsKey('verbPhrase')) {
        // Use the verbPhrase from the custom verb, not the label
        final verbPhrase = customVerb['verbPhrase'] as String? ?? resolvedVerb;
        final pluralPhrase = customVerb['pluralPhrase'] as String?;
        final usePluralPhrase = customVerb['usePluralPhrase'] as bool? ?? true;

        // Use plural phrase if we have multiple players and a plural phrase is defined
        if (activePlayerCount > 1 &&
            usePluralPhrase &&
            pluralPhrase != null &&
            pluralPhrase.isNotEmpty) {
          _popupCustomVerb = pluralPhrase;
        } else {
          _popupCustomVerb = verbPhrase;
        }
        _selectedVerb = resolvedVerb;
        _selectedActionVerb = resolvedVerb;
      } else {
        // Check if this is a verb override (for built-in verbs that were customized)
        if (_verbOverrides.containsKey(resolvedVerb)) {
          final override = _verbOverrides[resolvedVerb]!;
          final singularPhrase = override['verbPhrase'] as String?;
          final pluralPhrase = override['pluralPhrase'] as String?;
          final usePluralPhrase = override['usePluralPhrase'] as bool? ?? true;

          // Use plural phrase if we have multiple players and a plural phrase is defined
          if (activePlayerCount > 1 &&
              usePluralPhrase &&
              pluralPhrase != null &&
              pluralPhrase.isNotEmpty) {
            _popupCustomVerb = pluralPhrase;
          } else {
            _popupCustomVerb = singularPhrase ?? resolvedVerb;
          }
        } else {
          // For custom typed verbs (typed in the text field), use the text directly
          _popupCustomVerb = resolvedVerb;
        }
        _selectedVerb = resolvedVerb;
        _selectedActionVerb = resolvedVerb;
      }
    });
    _updateCaption();
  }

  // Helper function to remove diacritics (accents) from text
  String _removeDiacritics(String text) {
    const diacritics = {
      'á': 'a',
      'à': 'a',
      'ä': 'a',
      'â': 'a',
      'ã': 'a',
      'å': 'a',
      'Á': 'A',
      'À': 'A',
      'Ä': 'A',
      'Â': 'A',
      'Ã': 'A',
      'Å': 'A',
      'é': 'e',
      'è': 'e',
      'ë': 'e',
      'ê': 'e',
      'É': 'E',
      'È': 'E',
      'Ë': 'E',
      'Ê': 'E',
      'í': 'i',
      'ì': 'i',
      'ï': 'i',
      'î': 'i',
      'Í': 'I',
      'Ì': 'I',
      'Ï': 'I',
      'Î': 'I',
      'ó': 'o',
      'ò': 'o',
      'ö': 'o',
      'ô': 'o',
      'õ': 'o',
      'ø': 'o',
      'Ó': 'O',
      'Ò': 'O',
      'Ö': 'O',
      'Ô': 'O',
      'Õ': 'O',
      'Ø': 'O',
      'ú': 'u',
      'ù': 'u',
      'ü': 'u',
      'û': 'u',
      'Ú': 'U',
      'Ù': 'U',
      'Ü': 'U',
      'Û': 'U',
      'ñ': 'n',
      'Ñ': 'N',
      'ç': 'c',
      'Ç': 'C',
      'ý': 'y',
      'ÿ': 'y',
      'Ý': 'Y',
      'ß': 'ss',
      'æ': 'ae',
      'Æ': 'AE',
      'œ': 'oe',
      'Œ': 'OE',
    };

    String result = text;
    diacritics.forEach((key, value) {
      result = result.replaceAll(key, value);
    });
    return result;
  }

  // Public method to upload any image via FTP (called from thumbnail grid)
  Future<void> uploadImageViaFtp(String imagePath) async {
    // Check if FTP settings are configured
    if (_ftpHost.isEmpty || _ftpUsername.isEmpty || _ftpPassword.isEmpty) {
      throw Exception('Please configure FTP settings first!');
    }

    // Use original filename
    final originalFileName = p.basename(imagePath);
    final remoteFileName = originalFileName;

    // Build full remote path
    final fullRemotePath = _ftpRemotePath.isNotEmpty
        ? '${_ftpRemotePath.endsWith('/') ? _ftpRemotePath : '$_ftpRemotePath/'}$remoteFileName'
        : remoteFileName;

    print('FTP: Uploading $imagePath to $fullRemotePath');

    try {
      final result = await FtpClientService.uploadFile(
        localFilePath: imagePath,
        remoteFilePath: fullRemotePath,
        host: _ftpHost,
        username: _ftpUsername,
        password: _ftpPassword,
        port: _ftpPort,
        passiveMode: _ftpPassiveMode,
        onProgress: (status, progress, error) {
          // Notify parent about upload progress for overlay
          if (widget.onUploadProgress != null) {
            widget.onUploadProgress!(imagePath, progress);
          }
        },
      );

      if (result.success == true) {
        // Notify parent that image was uploaded successfully
        if (widget.onImageUploaded != null) {
          widget.onImageUploaded!(imagePath);
        }
      } else {
        throw Exception(result.error ?? 'FTP upload failed');
      }
    } catch (e) {
      throw e;
    }
  }

  Future<void> _onFtpPressed() async {
    // Store current metadata before saving for the "Last" button
    _storeCurrentMetadata();
    // Save IPTC metadata before uploading
    if (widget.onSaveIptc != null) {
      await widget.onSaveIptc!();
    }

    // Check if FTP settings are configured
    if (_ftpHost.isEmpty || _ftpUsername.isEmpty || _ftpPassword.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please configure FTP settings first!'),
          backgroundColor: Colors.orange,
          duration: Duration(seconds: 3),
        ),
      );
      return;
    }

    // Check if an image is selected
    if (widget.currentImagePath == null || widget.currentImagePath!.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please select an image first!'),
          backgroundColor: Colors.orange,
          duration: Duration(seconds: 3),
        ),
      );
      return;
    }

    // Check if already uploaded and prompt user
    if (widget.isImageUploaded != null &&
        widget.isImageUploaded!(widget.currentImagePath!)) {
      final shouldUpload = await showDialog<bool>(
        context: context,
        builder: (context) => Dialog(
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(4),
            side: const BorderSide(color: Colors.black, width: 1),
          ),
          backgroundColor: Colors.white,
          child: Container(
            padding: const EdgeInsets.all(16),
            constraints: const BoxConstraints(maxWidth: 400),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(4),
              border: Border.all(color: Colors.black, width: 1),
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                const Text(
                  'Already Uploaded',
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.bold,
                    color: Colors.black,
                  ),
                ),
                const SizedBox(height: 12),
                Text(
                  '${p.basename(widget.currentImagePath!)} has already been uploaded. Do you want to upload again?',
                  textAlign: TextAlign.center,
                  style: const TextStyle(
                    fontSize: 12,
                    color: Colors.black87,
                  ),
                ),
                const SizedBox(height: 16),
                Row(
                  mainAxisAlignment: MainAxisAlignment.end,
                  children: [
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(false),
                      child: Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 16,
                          vertical: 7,
                        ),
                        decoration: BoxDecoration(
                          color: Colors.grey.shade100,
                          borderRadius: BorderRadius.circular(4),
                          border: Border.all(color: Colors.grey.shade300),
                        ),
                        child: Text(
                          'Cancel',
                          style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w500,
                            color: Colors.grey.shade700,
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(width: 8),
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(true),
                      child: Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 16,
                          vertical: 7,
                        ),
                        decoration: BoxDecoration(
                          color: Colors.grey.shade100,
                          borderRadius: BorderRadius.circular(4),
                          border: Border.all(color: Colors.grey.shade300),
                        ),
                        child: Text(
                          'Upload Again',
                          style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w500,
                            color: Colors.grey.shade700,
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
      );

      if (shouldUpload != true) {
        return; // User cancelled
      }

      // Notify parent to remove from uploaded images so it can be uploaded again
      if (widget.onClearUploadStatus != null) {
        widget.onClearUploadStatus!(widget.currentImagePath!);
      }
    }

    // Use original filename
    final originalFileName = p.basename(widget.currentImagePath!);
    final remoteFileName = originalFileName;

    // Build full remote path
    final fullRemotePath = _ftpRemotePath.isNotEmpty
        ? '${_ftpRemotePath.endsWith('/') ? _ftpRemotePath : '$_ftpRemotePath/'}$remoteFileName'
        : remoteFileName;

    print('FTP: Generated remote filename: $remoteFileName');
    print('FTP: Remote path: $_ftpRemotePath');
    print('FTP: Full remote path: $fullRemotePath');

    // Progress will be shown over the thumbnail instead of a dialog
    String statusText = 'Connecting to FTP server...';
    String? errorText;

    try {
      // Folder watching disabled - no need to signal

      final result = await FtpClientService.uploadFile(
        host: _ftpHost,
        username: _ftpUsername,
        password: _ftpPassword,
        localFilePath: widget.currentImagePath!,
        remoteFilePath: fullRemotePath,
        port: _ftpPort,
        passiveMode: _ftpPassiveMode,
        onProgress: (status, progress, error) {
          statusText = status;
          errorText = error;
          // Notify parent about upload progress for overlay
          if (widget.onUploadProgress != null &&
              widget.currentImagePath != null) {
            widget.onUploadProgress!(widget.currentImagePath!, progress);
          }
        },
      );

      if (result.success) {
        setState(() {
          // No need to increment picture number when using original filenames
        });

        // Notify parent that image was uploaded successfully
        if (widget.onImageUploaded != null && widget.currentImagePath != null) {
          widget.onImageUploaded!(widget.currentImagePath!);
        }

        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Successfully uploaded: $remoteFileName'),
            backgroundColor: Colors.green,
            duration: const Duration(seconds: 3),
          ),
        );
      } else {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Upload failed: ${result.error}'),
            backgroundColor: Colors.red,
            duration: const Duration(seconds: 5),
          ),
        );
      }
    } catch (e) {
      Navigator.pop(context); // Close progress dialog
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Upload error: $e'),
          backgroundColor: Colors.red,
          duration: const Duration(seconds: 4),
        ),
      );
    }
  }

  // Folder picking functionality
  Future<void> _pickFolder() async {
    print('Starting folder picker...');
    final dirPath = await NativeFilePicker.pickDirectory();
    if (dirPath == null) {
      print('No folder selected');
      return;
    }

    print('Selected folder: $dirPath');

    // List image files
    final files = await _listImageFiles(dirPath);

    if (files.isNotEmpty) {
      // Notify parent about loaded images
      if (widget.onImagesLoaded != null) {
        widget.onImagesLoaded!(files);
      }

      // Start folder watcher
      if (widget.onStartFolderWatcher != null) {
        widget.onStartFolderWatcher!(dirPath);
      }

      // Show success message
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Loaded ${files.length} images from folder'),
          duration: const Duration(seconds: 2),
        ),
      );
    }
  }

