  String _capitalize(String text) {
    if (text.isEmpty) return text;
    // Handle multi-word cities like "New York"
    return text.split(' ').map((word) {
      if (word.isEmpty) return word;
      return word[0].toUpperCase() + word.substring(1).toLowerCase();
    }).join(' ');
  }

  String _combinePlayersWithSingleTeam(List<String> players) {
    if (players.isEmpty) return '';

    // Get full player names
    final playerNames = players.toList();

    // Determine the team from the first player's selection context
    final isHomeTeamPlayer = selectedHomePlayers.contains(players.first);
    final teamName = isHomeTeamPlayer ? selectedHomeTeam : selectedAwayTeam;

    if (teamName == null) {
      // Fallback to just player names if team is not available
      if (playerNames.length == 1) {
        return playerNames.first;
      } else if (playerNames.length == 2) {
        return '${playerNames[0]} and ${playerNames[1]}';
      } else {
        final last = playerNames.removeLast();
        return '${playerNames.join(', ')}, and $last';
      }
    }

    if (playerNames.length == 1) {
      return '${playerNames.first} of the $teamName';
    } else if (playerNames.length == 2) {
      // Two players: "Player1 and Player2 of the team"
      return '${playerNames[0]} and ${playerNames[1]} of the $teamName';
    } else {
      // Three or more players: "Player1, Player2, and Player3 of the team"
      final last = playerNames.removeLast();
      return '${playerNames.join(', ')}, and $last of the $teamName';
    }
  }

  // Helper to get verb phrase from overrides based on player count
  String? _getOverriddenVerbPhrase(String verbLabel, int playerCount) {
    // First, try direct lookup by label (the key used when saving built-in verb overrides)
    if (_verbOverrides.containsKey(verbLabel)) {
      final override = _verbOverrides[verbLabel]!;
      final singularPhrase = override['verbPhrase'] as String?;
      final pluralPhrase = override['pluralPhrase'] as String?;
      final usePluralPhrase = override['usePluralPhrase'] as bool? ?? true;

      if (playerCount > 1 &&
          usePluralPhrase &&
          pluralPhrase != null &&
          pluralPhrase.isNotEmpty) {
        return pluralPhrase;
      }
      return singularPhrase;
    }

    // Fallback: Find the override by checking each override's label field
    for (final entry in _verbOverrides.entries) {
      final override = entry.value;
      final overrideLabel = override['label'] as String?;
      if (overrideLabel == verbLabel) {
        // Found an override for this verb
        final singularPhrase = override['verbPhrase'] as String?;
        final pluralPhrase = override['pluralPhrase'] as String?;
        final usePluralPhrase = override['usePluralPhrase'] as bool? ?? true;

        if (playerCount > 1 &&
            usePluralPhrase &&
            pluralPhrase != null &&
            pluralPhrase.isNotEmpty) {
          return pluralPhrase;
        }
        return singularPhrase;
      }
    }
    return null; // No override found
  }

  /// Map a display label back to the built-in verb key stored in [_verbOverrides].
  ///
  /// The player popup passes [VerbOption.label], which may be an edited display name
  /// (e.g. "Goes to the Net Against") while switch/caption logic keys off the default
  /// name ("Goes to the Net"). Without this, those verbs fall through to the baseball
  /// default and produce "hits a …".
  String _resolveCanonicalVerbKey(String verb) {
    final v = verb.trim();
    if (v.isEmpty) return verb;

    // Legacy list accidentally used this label as the verb key; map to canonical.
    if (v == 'Goes to the Net Against') {
      return 'Goes to the Net';
    }

    if (_verbOverrides.containsKey(v)) return v;
    for (final entry in _verbOverrides.entries) {
      final label = entry.value['label'] as String?;
      // Only remap when the override key is a canonical verb name (starts with
      // an uppercase letter, e.g. "Saves", "Guards the Net", "Goes to the Net").
      // Stale overrides incorrectly stored the computed verbPhrase as the key
      // (e.g. "makes a save", "guards the net against") — these are always
      // all-lowercase and would redirect the canonical input to the default
      // baseball path, producing "hits a …" in hockey captions.
      if (label != null &&
          label.trim() == v &&
          entry.key.isNotEmpty &&
          RegExp(r'^[A-Z]').hasMatch(entry.key)) {
        return entry.key;
      }
    }
    // Always use trimmed form so switch cases match.
    return v;
  }

  // Helper to check if "against" should be omitted for a verb
  bool _shouldOmitAgainst(String verbLabel) {
    // First, try direct lookup by label (the key used when saving built-in verb overrides)
    if (_verbOverrides.containsKey(verbLabel)) {
      final override = _verbOverrides[verbLabel]!;
      return override['omitAgainst'] as bool? ?? false;
    }

    // Fallback: Find the override by checking each override's label field
    for (final entry in _verbOverrides.entries) {
      final override = entry.value;
      final overrideLabel = override['label'] as String?;
      if (overrideLabel == verbLabel) {
        return override['omitAgainst'] as bool? ?? false;
      }
    }
    return false; // Default: include "against"
  }

  String _buildActionPhrase() {
    final rawVerb = _selectedActionVerb ?? _selectedVerb;
    if (rawVerb == null) return '';
    final originalVerb = _resolveCanonicalVerbKey(rawVerb);

    if (_popupCustomVerb != null && _popupCustomVerb!.isNotEmpty) {
      return _popupCustomVerb!;
    }

    String baseAction = '';

    final String? customWordingFromPrefs = _customVerbWordings[originalVerb];
    final bool hasCustomWordingFromPrefs = customWordingFromPrefs != null &&
        customWordingFromPrefs.trim().isNotEmpty;

    // Get the count of active players for plural/singular verb forms
    // For verbs that require opponents, count only the first team selected (the team doing the action)
    // For other verbs, count all selected players
    final bool requiresOpponent = originalVerb == 'Battles' ||
        originalVerb == 'Shoots' ||
        originalVerb == 'Skates' ||
        originalVerb == 'Scores' ||
        originalVerb == 'Goes to the Net' ||
        originalVerb == 'Faceoff' ||
        originalVerb == 'Checks' ||
        originalVerb == 'Defends' ||
        originalVerb == 'Blocks' ||
        // Basketball opponent verbs
        originalVerb == 'Drives' ||
        originalVerb == 'Dribbles' ||
        originalVerb == 'Dunks' ||
        originalVerb == 'Lays Up' ||
        originalVerb == 'Three-Pointer' ||
        originalVerb == 'Free Throw' ||
        originalVerb == 'Steals the Ball' ||
        originalVerb == 'Contests' ||
        originalVerb == 'Rebounds';

    final activePlayerCount = requiresOpponent && _firstTeamSelected != null
        ? (_firstTeamSelected!
            ? selectedHomePlayers.length
            : selectedAwayPlayers.length)
        : (selectedHomePlayers.length + selectedAwayPlayers.length);

    // Full verb editor (override) takes precedence over simple custom wording map.
    final String? overriddenPhrase =
        _getOverriddenVerbPhrase(originalVerb, activePlayerCount);
    final bool hasOverridePhrase =
        overriddenPhrase != null && overriddenPhrase.trim().isNotEmpty;
    final String? resolvedVerbPhrase = hasOverridePhrase
        ? overriddenPhrase!.trim()
        : (hasCustomWordingFromPrefs ? customWordingFromPrefs!.trim() : null);
    final bool hasResolvedVerbPhrase =
        resolvedVerbPhrase != null && resolvedVerbPhrase.isNotEmpty;

    // Use original verb for switch logic, but custom wording for output
    switch (originalVerb) {
      case 'Single':
        baseAction = 'single';
        break;
      case 'Double':
        baseAction = 'double';
        break;
      case 'Triple':
        baseAction = 'triple';
        break;
      case 'Home Run':
        baseAction = _buildHomeRunPhrase();
        break;
      case 'Sacrifice Fly':
        baseAction = 'sacrifice fly';
        break;
      case 'Strikeout':
        baseAction = 'strikeout';
        break;
      case 'Grand Slam':
        baseAction = 'grand slam';
        break;
      case 'At Bat':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'takes an at bat in his batting stance against the ${_getOpposingTeamName()}';
      case 'Pitching':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'delivers a pitch against the ${_getOpposingTeamName()}';
      case 'Swings':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'swings against the ${_getOpposingTeamName()}';
      case 'Bunts':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'bunts against the ${_getOpposingTeamName()}';
      case 'Hit by Pitch':
        if (hasResolvedVerbPhrase) {
          // Check if opposing players are selected
          final opposingPlayers = _getOpposingPlayers();
          if (opposingPlayers.isNotEmpty) {
            final pitcherName = _formatPlayersWithTeam(opposingPlayers);
            return '$resolvedVerbPhrase by $pitcherName';
          } else {
            final opposingTeam = _getOpposingTeamName();
            return '$resolvedVerbPhrase against the $opposingTeam';
          }
        }
        // Check if opposing players are selected
        final opposingPlayers = _getOpposingPlayers();
        if (opposingPlayers.isNotEmpty) {
          final pitcherName = _formatPlayersWithTeam(opposingPlayers);
          return 'is hit by a pitch by $pitcherName';
        } else {
          final opposingTeam = _getOpposingTeamName();
          return 'gets hit by a pitch against the $opposingTeam';
        }
      case 'Walks':
        if (hasResolvedVerbPhrase) {
          // Check if opposing players are selected
          final opposingPlayersWalks = _getOpposingPlayers();
          if (opposingPlayersWalks.isNotEmpty) {
            final pitcherName = _formatPlayersWithTeam(opposingPlayersWalks);
            return '$resolvedVerbPhrase against $pitcherName';
          } else {
            final opposingTeam = _getOpposingTeamName();
            return '$resolvedVerbPhrase against the $opposingTeam';
          }
        }
        // Check if opposing players are selected
        final opposingPlayersWalks = _getOpposingPlayers();
        if (opposingPlayersWalks.isNotEmpty) {
          final pitcherName = _formatPlayersWithTeam(opposingPlayersWalks);
          return 'takes a walk against $pitcherName';
        } else {
          final opposingTeam = _getOpposingTeamName();
          return 'takes a walk against the $opposingTeam';
        }
      case 'Fielding Position':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'takes fielding position against the ${_getOpposingTeamName()}';

      case 'Looks On':
        // Check if multiple players are selected
        final activePlayers = selectedHomePlayers.union(selectedAwayPlayers);
        final isMultiplePlayers = activePlayers.length > 1;

        if (_isPriorToGame) {
          return isMultiplePlayers ? 'look on' : 'looks on';
        } else {
          final action = isMultiplePlayers ? 'look on' : 'looks on';
          return '$action against the ${_getOpposingTeamName()}';
        }
      case 'Walks Off Field':
        return 'walks off the field against the ${_getOpposingTeamName()}';
      case 'Runs Off Field':
        return 'runs off the field against the ${_getOpposingTeamName()}';
      case 'Takes the Field':
        if (_isPriorToGame) {
          return 'takes the field';
        } else {
          return 'takes the field against the ${_getOpposingTeamName()}';
        }
      case 'Comes Off the Field':
        if (_isPriorToGame) {
          return 'comes off the field';
        } else {
          return 'comes off the field against the ${_getOpposingTeamName()}';
        }
      case 'National Anthem':
        if (overriddenPhrase != null && overriddenPhrase.isNotEmpty) {
          return overriddenPhrase;
        }
        if ((widget.sport?.toLowerCase() ?? 'baseball') == 'baseball') {
          final activePlayersAnthem =
              selectedHomePlayers.union(selectedAwayPlayers);
          final isMultipleAnthem = activePlayersAnthem.length > 1;
          final actionAnthem = isMultipleAnthem ? 'look on' : 'looks on';
          return hasResolvedVerbPhrase
              ? '$resolvedVerbPhrase during the national anthem prior to play against the ${_getOpposingTeamName()}'
              : '$actionAnthem during the national anthem prior to play against the ${_getOpposingTeamName()}';
        } else {
          if (activePlayerCount >= 2) {
            return hasResolvedVerbPhrase
                ? resolvedVerbPhrase
                : 'stand for the national anthem';
          } else {
            return hasResolvedVerbPhrase
                ? resolvedVerbPhrase
                : 'stands for the national anthem';
          }
        }
      case 'Stretching':
        if (overriddenPhrase != null && overriddenPhrase.isNotEmpty) {
          return overriddenPhrase;
        }
        if ((widget.sport?.toLowerCase() ?? 'baseball') == 'baseball') {
          final activePlayersStretching =
              selectedHomePlayers.union(selectedAwayPlayers);
          final isMultiplePlayersStretching =
              activePlayersStretching.length > 1;
          final actionStretching =
              isMultiplePlayersStretching ? 'stretch' : 'stretches';
          return hasResolvedVerbPhrase
              ? '$resolvedVerbPhrase prior to play against the ${_getOpposingTeamName()}'
              : '$actionStretching prior to play against the ${_getOpposingTeamName()}';
        } else {
          if (activePlayerCount >= 2) {
            return hasResolvedVerbPhrase ? resolvedVerbPhrase : 'stretch';
          } else {
            return hasResolvedVerbPhrase ? resolvedVerbPhrase : 'stretches';
          }
        }
      case 'Warm Ups':
        if (overriddenPhrase != null && overriddenPhrase.isNotEmpty) {
          return overriddenPhrase;
        }
        if ((widget.sport?.toLowerCase() ?? 'baseball') == 'baseball') {
          final activePlayersWarmUps =
              selectedHomePlayers.union(selectedAwayPlayers);
          final isMultiplePlayersWarmUps = activePlayersWarmUps.length > 1;
          final actionWarmUps = isMultiplePlayersWarmUps
              ? 'take part in warm ups'
              : 'takes part in warm ups';
          return hasResolvedVerbPhrase
              ? '$resolvedVerbPhrase prior to play against the ${_getOpposingTeamName()}'
              : '$actionWarmUps prior to play against the ${_getOpposingTeamName()}';
        } else {
          if (activePlayerCount >= 2) {
            return hasResolvedVerbPhrase ? resolvedVerbPhrase : 'warm up';
          } else {
            return hasResolvedVerbPhrase ? resolvedVerbPhrase : 'warms up';
          }
        }
      case 'Pitching Change':
        String inningText = '';
        if (_selectedRbiInning != null) {
          inningText =
              ' during the ${_getOrdinalSuffix(_selectedRbiInning!)} inning';
        }

        // Get selected players
        final selectedPlayers = selectedHomePlayers.isNotEmpty
            ? selectedHomePlayers
            : selectedAwayPlayers;

        if (selectedPlayers.isNotEmpty) {
          final firstPlayer = selectedPlayers.first;
          // Get team name for the first player
          final isHomeTeamPlayer = selectedHomePlayers.contains(firstPlayer);
          final teamName =
              isHomeTeamPlayer ? selectedHomeTeam : selectedAwayTeam;
          final firstPlayerName = '$firstPlayer of the $teamName';

          // Get remaining players for "stand on the mound" part
          final remainingPlayers = selectedPlayers.skip(1).toList();

          if (_managerName.isNotEmpty) {
            if (remainingPlayers.isNotEmpty) {
              final remainingPlayerNames = remainingPlayers.length == 1
                  ? remainingPlayers.first
                  : '${remainingPlayers.take(remainingPlayers.length - 1).join(', ')}, and ${remainingPlayers.last}';
              return '$firstPlayerName is taken out of the game by manager $_managerName as $remainingPlayerNames stand on the mound in a break in play$inningText against the ${_getOpposingTeamName()}';
            } else {
              return '$firstPlayerName is taken out of the game by manager $_managerName in a break in play$inningText against the ${_getOpposingTeamName()}';
            }
          } else {
            if (remainingPlayers.isNotEmpty) {
              final remainingPlayerNames = remainingPlayers.length == 1
                  ? remainingPlayers.first
                  : '${remainingPlayers.take(remainingPlayers.length - 1).join(', ')}, and ${remainingPlayers.last}';
              return '$firstPlayerName is taken out of the game as $remainingPlayerNames stand on the mound in a break in play$inningText against the ${_getOpposingTeamName()}';
            } else {
              return '$firstPlayerName is taken out of the game in a break in play$inningText against the ${_getOpposingTeamName()}';
            }
          }
        } else {
          if (_managerName.isNotEmpty) {
            return 'pitcher taken out of the game by manager $_managerName$inningText against the ${_getOpposingTeamName()}';
          } else {
            return 'pitcher taken out of the game$inningText against the ${_getOpposingTeamName()}';
          }
        }
      case 'Catches':
        if (hasResolvedVerbPhrase) {
          return '$resolvedVerbPhrase against the ${_getOpposingTeamName()}';
        }
        if (_selectedFieldingAction == 'Diving Catch' || _isDivingCatch) {
          return 'makes a diving catch against the ${_getOpposingTeamName()}';
        } else {
          return 'catches a ball against the ${_getOpposingTeamName()}';
        }
      case 'Throws':
        return hasResolvedVerbPhrase
            ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
            : 'throws a ball against the ${_getOpposingTeamName()}';
      case 'Tags':
        if (_selectedTagsAction != null) {
          // Handle On the Base Path as a special case first
          if (_selectedTagsAction == 'Tags Runner Out at: On the Base Path') {
            final opposingTeam = _getOpposingTeamName();
            final secondPlayer = _getSecondPlayer();
            if (secondPlayer != null) {
              return 'tags $secondPlayer out on the base path against the $opposingTeam';
            } else {
              return 'tags a runner out on the base path against the $opposingTeam';
            }
          }

          // Parse the tags action to build proper caption
          final parts = _selectedTagsAction!.split(' - ');
          if (parts.length == 2) {
            final base = parts[0].replaceAll('Tags Runner Out at: ', '');
            final action = parts[1].toLowerCase();

            // Convert base to full word
            String fullBaseName;
            switch (base) {
              case '1st':
                fullBaseName = 'first base';
                break;
              case '2nd':
                fullBaseName = 'second base';
                break;
              case '3rd':
                fullBaseName = 'third base';
                break;
              case 'Home':
                fullBaseName = 'home plate';
                break;
              case 'On the Base Path':
                fullBaseName = 'on the base path';
                break;
              default:
                fullBaseName = base.toLowerCase();
            }

            // Get the second player (the one being tagged out)
            final secondPlayer = _getSecondPlayer();
            if (secondPlayer != null) {
              if (action == 'stealing') {
                return 'tags $secondPlayer out at $fullBaseName on a stealing attempt';
              } else if (action == 'pickoff') {
                return 'tags $secondPlayer out at $fullBaseName on a pickoff';
              } else if (action == 'attempting to advance') {
                return 'tags $secondPlayer out at $fullBaseName attempting to advance';
              } else if (action == 'attempting to score') {
                return 'tags $secondPlayer out at $fullBaseName attempting to score';
              } else if (fullBaseName == 'on the base path') {
                final opposingTeam = _getOpposingTeamName();
                return 'tags $secondPlayer out on the base path against the $opposingTeam';
              } else {
                return 'tags $secondPlayer out at $fullBaseName $action';
              }
            } else {
              if (action == 'stealing') {
                return 'tags a runner out at $fullBaseName on a stealing attempt';
              } else if (action == 'pickoff') {
                return 'tags a runner out at $fullBaseName on a pickoff';
              } else if (action == 'attempting to advance') {
                return 'tags a runner out at $fullBaseName attempting to advance';
