        final dunksPhrase = resolvedVerbPhrase ?? 'dunks';
        final dunksOmit = _shouldOmitAgainst(originalVerb);
        final dunksAgainst = dunksOmit ? '' : ' against';
        if (dunksOpp.isNotEmpty) {
          return '$dunksPhrase$dunksAgainst ${_formatPlayersWithTeam(dunksOpp)}';
        }
        return '$dunksPhrase$dunksAgainst the ${_getOpposingTeamName()}';

      case 'Lays Up':
        final layupOpp = _getOpposingPlayers();
        final layupPhrase = resolvedVerbPhrase ?? 'lays up';
        final layupOmit = _shouldOmitAgainst(originalVerb);
        final layupAgainst = layupOmit ? '' : ' against';
        if (layupOpp.isNotEmpty) {
          return '$layupPhrase$layupAgainst ${_formatPlayersWithTeam(layupOpp)}';
        }
        return '$layupPhrase$layupAgainst the ${_getOpposingTeamName()}';

      case 'Dribbles':
        final dribblesOpp = _getOpposingPlayers();
        final dribblesPhrase = resolvedVerbPhrase ?? 'dribbles';
        final dribblesOmit = _shouldOmitAgainst(originalVerb);
        final dribblesAgainst = dribblesOmit ? '' : ' against';
        if (dribblesOpp.isNotEmpty) {
          return '$dribblesPhrase$dribblesAgainst ${_formatPlayersWithTeam(dribblesOpp)}';
        }
        return '$dribblesPhrase$dribblesAgainst the ${_getOpposingTeamName()}';

      case 'Three-Pointer':
        final threeOpp = _getOpposingPlayers();
        final threePhrase = overriddenPhrase ??
            (hasResolvedVerbPhrase
                ? resolvedVerbPhrase
                : 'makes a three-pointer');
        final threeOmit = _shouldOmitAgainst(originalVerb);
        final threeAgainst = threeOmit ? '' : ' against';
        if (threeOpp.isNotEmpty) {
          return '$threePhrase$threeAgainst ${_formatPlayersWithTeam(threeOpp)}';
        }
        return '$threePhrase$threeAgainst the ${_getOpposingTeamName()}';

      case 'Free Throw':
        final ftOpp = _getOpposingPlayers();
        final ftPhrase = overriddenPhrase ??
            (hasResolvedVerbPhrase
                ? resolvedVerbPhrase
                : 'shoots a free throw');
        final ftOmit = _shouldOmitAgainst(originalVerb);
        final ftAgainst = ftOmit ? '' : ' against';
        if (ftOpp.isNotEmpty) {
          return '$ftPhrase$ftAgainst ${_formatPlayersWithTeam(ftOpp)}';
        }
        return '$ftPhrase$ftAgainst the ${_getOpposingTeamName()}';

      case 'Steals the Ball':
        final stealOpp = _getOpposingPlayers();
        final stealPhrase = overriddenPhrase ??
            (hasResolvedVerbPhrase
                ? resolvedVerbPhrase
                : 'steals the ball from');
        if (stealOpp.isNotEmpty) {
          return '$stealPhrase ${_formatPlayersWithTeam(stealOpp)}';
        }
        return '$stealPhrase the ${_getOpposingTeamName()}';

      case 'Contests':
        final contestsOpp = _getOpposingPlayers();
        final contestsPhrase = overriddenPhrase ??
            (hasResolvedVerbPhrase ? resolvedVerbPhrase : 'contests a shot by');
        if (contestsOpp.isNotEmpty) {
          return '$contestsPhrase ${_formatPlayersWithTeam(contestsOpp)}';
        }
        return '$contestsPhrase the ${_getOpposingTeamName()}';

      case 'Rebounds':
        final reboundOpp = _getOpposingPlayers();
        final reboundPhrase = overriddenPhrase ??
            (hasResolvedVerbPhrase ? resolvedVerbPhrase : 'rebounds');
        final reboundOmit = _shouldOmitAgainst(originalVerb);
        final reboundAgainst = reboundOmit ? '' : ' against';
        if (reboundOpp.isNotEmpty) {
          return '$reboundPhrase$reboundAgainst ${_formatPlayersWithTeam(reboundOpp)}';
        }
        return '$reboundPhrase$reboundAgainst the ${_getOpposingTeamName()}';

      case 'Takes the Court':
        if (activePlayerCount >= 2) {
          return hasResolvedVerbPhrase
              ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
              : 'take the court against the ${_getOpposingTeamName()}';
        } else {
          return hasResolvedVerbPhrase
              ? '$resolvedVerbPhrase against the ${_getOpposingTeamName()}'
              : 'takes the court against the ${_getOpposingTeamName()}';
        }

      case 'Comes Off the Court':
        if (activePlayerCount >= 2) {
          return hasResolvedVerbPhrase
              ? resolvedVerbPhrase ?? 'come off the court'
              : 'come off the court';
        } else {
          return hasResolvedVerbPhrase
              ? resolvedVerbPhrase ?? 'comes off the court'
              : 'comes off the court';
        }

      default:
        baseAction = originalVerb.toLowerCase();
    }

    // Apply custom wording override to base action (except Home Run handled below)
    if (hasResolvedVerbPhrase && originalVerb != 'Home Run') {
      baseAction = resolvedVerbPhrase!;
    }

    // Build the hit phrase
    String hitPhrase = '';
    final bool isHomeRunAction = originalVerb == 'Home Run';
    if (!isHomeRunAction && _rbiCount != null && _rbiCount! > 0) {
      final rbiText =
          _rbiCount == 1 ? 'RBI' : '${_numberToWord(_rbiCount!)}-RBI';
      hitPhrase = 'hits a $rbiText $baseAction';
    } else {
      hitPhrase = 'hits a $baseAction';
    }
    // Add celebration action if specified
    if (_selectedHittingAction != null) {
      switch (_selectedHittingAction!) {
        case 'celebrates':
        case 'celebrates_in_dugout':
          // Get teammates (other players from the same team as the main player)
          final teammates = _getTeammates();

          // For dugout celebration, if no teammates, don't include teammate phrase
          final teammatePhrase = (_selectedHittingAction ==
                      'celebrates_in_dugout' &&
                  teammates.isEmpty)
              ? ''
              : (teammates.isNotEmpty
                  ? ' with ${teammates.length == 1 ? 'teammate' : 'teammates'} ${_formatPlayerNames(teammates)}'
                  : '');

          // Include opposing players if selected, otherwise use opposing team
          final opposingPlayers = _getOpposingPlayers();
          final opposingTeam = _getOpposingTeamName();
          final againstPhrase = opposingPlayers.isNotEmpty
              ? ' against ${_formatPlayerNames(opposingPlayers)}${opposingTeam != null ? ' of the $opposingTeam' : ''}'
              : (opposingTeam != null ? ' against the $opposingTeam' : '');

          const celebrationType = 'celebrates';
          final dugoutPhrase = _selectedHittingAction == 'celebrates_in_dugout'
              ? ' in the dugout'
              : '';

          if (_rbiCount != null && _rbiCount! > 0) {
            final rbiText =
                _rbiCount == 1 ? 'RBI' : '${_numberToWord(_rbiCount!)}-RBI';
            return '$celebrationType a $rbiText $baseAction$dugoutPhrase$teammatePhrase$againstPhrase';
          } else {
            return '$celebrationType a $baseAction$dugoutPhrase$teammatePhrase$againstPhrase';
          }
        case 'runs_base_paths':
          return 'runs the base path on $baseAction';
        case 'runs to first base':
          return 'runs to first base on a $baseAction';
        case 'trots_the_bases':
          // Get opposing players if any are selected
          final opposingPlayers = _getOpposingPlayers();
          final opposingTeam = _getOpposingTeamName();

          if (opposingPlayers.isNotEmpty) {
            // If opposing players are selected, use "past [player names] of the [team]"
            final playerNames = _formatPlayerNames(opposingPlayers);
            final teamPhrase =
                opposingTeam != null ? ' of the $opposingTeam' : '';
            return 'trots the bases on his $baseAction past $playerNames$teamPhrase';
          } else if (opposingTeam != null) {
            // If no opposing players but team is available, use "against the [team]"
            return 'trots the bases on his $baseAction against the $opposingTeam';
          } else {
            // Fallback
            return 'trots the bases on his $baseAction';
          }
        case 'slides_into_base':
          final baseToSlideInto = _getBaseToSlideInto(baseAction);
          return 'slides into $baseToSlideInto on a $baseAction';
        default:
          return hitPhrase;
      }
    }

    return hitPhrase;
  }

  String _numberToWord(int number) {
    switch (number) {
      case 1:
        return 'one';
      case 2:
        return 'two';
      case 3:
        return 'three';
      case 4:
        return 'four';
      case 5:
        return 'five';
      case 6:
        return 'six';
      case 7:
        return 'seven';
      case 8:
        return 'eight';
      case 9:
        return 'nine';
      case 10:
        return 'ten';
      default:
        return number.toString();
    }
  }

  String _getBaseToSlideInto(String hitType) {
    switch (hitType) {
      case 'single':
        return 'first base';
      case 'double':
        return 'second base';
      case 'triple':
        return 'third base';
      case 'home run':
      case 'solo home run':
      case 'two-run home run':
      case 'three-run home run':
      case 'grand slam':
        return 'home plate';
      default:
        return 'base';
    }
  }

  List<String> _getTeammates() {
    // Get teammates (other players from the same team as the main player)
    if (_firstPlayerSelected == null) return [];

    // Determine which team the main player is from using normalized comparison
    final isMainPlayerHome = selectedHomePlayers.any(
      (player) => _removeJerseyNumberFromName(player) == _firstPlayerSelected,
    );

    // Get all players from the same team, excluding the main player (normalized)
    final Iterable<String> source =
        isMainPlayerHome ? selectedHomePlayers : selectedAwayPlayers;
    final teammates = source
        .where(
          (player) =>
              _removeJerseyNumberFromName(player) != _firstPlayerSelected,
        )
        .toList();

    return teammates;
  }

