        // Action options
        Expanded(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Home Run Type section with buttons
              Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Container(
                    margin: const EdgeInsets.only(left: 8, right: 8, top: 4),
                    child: const Text(
                      'Home Run Type',
                      style: TextStyle(
                        fontSize: 12,
                        fontWeight: FontWeight.w500,
                        color: Colors.grey,
                      ),
                    ),
                  ),
                  const SizedBox(height: 2),
                  Container(
                    width: double.infinity,
                    margin: const EdgeInsets.only(left: 8, right: 8, bottom: 8),
                    child: Wrap(
                      spacing: 2,
                      runSpacing: 2,
                      children:
                          ['Solo', 'Two-Run', 'Three-Run', 'Grand Slam'].map((
                        hrType,
                      ) {
                        final isSelected = _selectedHomeRunType == hrType;
                        return GestureDetector(
                          onTap: () {
                            setState(() {
                              _selectedHomeRunType =
                                  _selectedHomeRunType == hrType
                                      ? null
                                      : hrType;
                            });
                            _updateCaption();
                          },
                          child: Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 8,
                              vertical: 5,
                            ),
                            decoration: BoxDecoration(
                              color: isSelected
                                  ? Colors.grey.shade300
                                  : Colors.grey.shade50,
                              borderRadius: BorderRadius.circular(3),
                              border: Border.all(
                                color: Colors.grey.shade300,
                                width: 0.5,
                              ),
                            ),
                            child: Builder(
                              builder: (context) {
                                final String typed = _magicBarVerbInput;
                                final RegExpMatch? lettersMatch = RegExp(
                                  r'([a-zA-Z]+)$',
                                ).firstMatch(typed);
                                final String typedLetters =
                                    lettersMatch?.group(1)?.toLowerCase() ?? '';

                                // Build shortcut: multi-word -> acronym, single-word -> first 2-3
                                List<String> words = RegExp(r'[A-Za-z]+')
                                    .allMatches(hrType)
                                    .map((m) => m.group(0)!)
                                    .toList();
                                String shortcut;
                                if (words.length > 1) {
                                  shortcut = words
                                      .map((w) => w[0].toLowerCase())
                                      .join();
                                } else {
                                  final w = words.first.toLowerCase();
                                  shortcut =
                                      w.length >= 2 ? w.substring(0, 2) : w;
                                }

                                String boldPart = '';
                                if (_magicBarFocusNode.hasFocus &&
                                    typedLetters.isNotEmpty &&
                                    shortcut.startsWith(typedLetters)) {
                                  boldPart = hrType.substring(
                                    0,
                                    typedLetters.length.clamp(0, hrType.length),
                                  );
                                } else if (_magicBarFocusNode.hasFocus) {
                                  boldPart = hrType.substring(
                                    0,
                                    shortcut.length.clamp(0, hrType.length),
                                  );
                                }

                                return RichText(
                                  maxLines: 1,
                                  overflow: TextOverflow.ellipsis,
                                  text: TextSpan(
                                    children: [
