                              _extraInningsPage--;
                            } else {
                              // Go back to regular innings
                              _showExtraInnings = false;
                              _extraInningsPage = 0;
                              _selectedRbiInning = null;
                            }
                          });
                        },
                        child: Container(
                          width: 28,
                          height: 28,
                          alignment: Alignment.center,
                          decoration: BoxDecoration(
                            color: Colors.grey.shade50,
                            borderRadius: BorderRadius.circular(3),
                            border: Border.all(
                              color: Colors.grey.shade300,
                              width: 0.5,
                            ),
                          ),
                          child: Text(
                            '←',
                            style: TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w500,
                              color: Colors.grey.shade700,
                            ),
                          ),
                        ),
                      ),
                    // Innings (regular or extra based on state)
                    ...(_showExtraInnings
                            ? _getExtraInningsForPage()
                            : List.generate(9, (index) => index + 1))
                        .map((inning) {
                      final isSelected = _selectedRbiInning == inning;
                      return GestureDetector(
                        onTap: () {
                          setState(() {
                            _selectedRbiInning =
                                _selectedRbiInning == inning ? null : inning;
                          });
                          _updateCaption();
                        },
                        child: Container(
                          width: 28,
                          height: 28,
                          alignment: Alignment.center,
                          decoration: BoxDecoration(
                            color: isSelected
                                ? Colors.grey.shade300
                                : Colors.grey.shade50,
                            borderRadius: BorderRadius.circular(3),
                            border: Border.all(
                              color: Colors.grey.shade300,
                              width: 0.5,
                            ),
                          ),
                          child: Text(
                            '$inning',
                            style: TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w500,
                              color: Colors.grey.shade700,
                            ),
                          ),
                        ),
                      );
                    }),
                    // EXT button that cycles through extra innings
                    GestureDetector(
                      onTap: () {
                        setState(() {
                          if (_showExtraInnings) {
                            // If already showing extra innings, go to next page
                            if (_extraInningsPage < 3) {
                              _extraInningsPage++;
                            } else {
                              // Go back to regular innings
                              _showExtraInnings = false;
                              _extraInningsPage = 0;
                              _selectedRbiInning = null;
                            }
                          } else {
                            // Start showing extra innings
                            _showExtraInnings = true;
                            _extraInningsPage = 0;
                            _selectedRbiInning = null;
                          }
                        });
                      },
                      child: Container(
                        width: 28,
                        height: 28,
                        alignment: Alignment.center,
                        decoration: BoxDecoration(
                          color: _showExtraInnings
                              ? Colors.grey.shade300
                              : Colors.grey.shade50,
                          borderRadius: BorderRadius.circular(3),
                          border: Border.all(
                            color: Colors.grey.shade300,
                            width: 0.5,
                          ),
