  // Reusable inning selector widget
  Widget _buildReusableInningSelector() {
    // Always hide the background inning selector - only show innings in popup
    // Return empty container to maintain layout structure
    return Container(
      width: double.infinity,
      margin: const EdgeInsets.only(left: 8, right: 0, bottom: 8),
      child: const SizedBox.shrink(),
    );

    // Original code kept for reference but never executed
    // Determine which innings to show based on the current state
    List<int> inningsToShow;
    int currentPage =
        _extraInningsPage; // Use existing _extraInningsPage variable

    if (currentPage == 0) {
      inningsToShow = List.generate(9, (index) => index + 1); // 1-9
    } else if (currentPage == 1) {
      inningsToShow = List.generate(9, (index) => index + 10); // 10-18
    } else {
      inningsToShow = List.generate(9, (index) => index + 19); // 19-27
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Container(
          margin: const EdgeInsets.only(left: 8, right: 0, top: 4),
          child: const Text(
            'Inning',
            style: TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w500,
              color: Colors.grey,
            ),
          ),
        ),
        const SizedBox(height: 2),

        // Innings section (changes content based on state)
        Container(
          width: double.infinity,
          margin: const EdgeInsets.only(left: 8, right: 0, bottom: 8),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Innings row
              Wrap(
                spacing: 2,
                runSpacing: 2,
                children: [
                  // Current set of innings
                  ...inningsToShow.map((inning) {
                    final isSelected = _selectedRbiInning == inning;
                    return GestureDetector(
                      onTap: () {
                        setState(() {
                          _selectedRbiInning =
                              _selectedRbiInning == inning ? null : inning;
                          if (_selectedRbiInning != null) {
                            _isPriorToGame = false;
                          }
                        });
                        _updateCaption();
                      },
                      child: Container(
                        width: 36,
                        height: 33,
                        alignment: Alignment.center,
                        decoration: BoxDecoration(
                          color: isSelected
                              ? Colors.grey.shade300
                              : Colors.grey.shade50,
                          borderRadius: BorderRadius.circular(3),
                          border: Border.all(
                            color: Colors.grey.shade300,
                            width: 0.5,
                          ),
                        ),
                        child: Text(
                          '$inning',
                          style: TextStyle(
                            fontSize: 10,
                            fontWeight: FontWeight.w500,
                            color: isSelected
                                ? Colors.white
                                : Colors.grey.shade700,
                          ),
                        ),
                      ),
                    );
                  }),

                  // Minus button (go back to previous set)
                  GestureDetector(
                    onTap: currentPage > 0
                        ? () {
                            setState(() {
                              _extraInningsPage--;
                              if (_extraInningsPage == 0) {
                                _showExtraInnings = false;
                              }
                              _selectedRbiInning =
                                  null; // Clear selection when switching
                              _isPriorToGame = false; // Clear prior selection
                            });
                            _updateCaption();
                          }
                        : null,
                    child: Container(
                      width: 36,
                      height: 33,
                      alignment: Alignment.center,
                      decoration: BoxDecoration(
                        color: currentPage > 0
                            ? Colors.grey.shade50
                            : Colors.grey.shade200,
                        borderRadius: BorderRadius.circular(3),
                        border: Border.all(color: Colors.grey.shade300),
                      ),
                      child: Text(
                        '-',
                        style: TextStyle(
                          fontSize: 14,
                          fontWeight: FontWeight.w500,
                          color: currentPage > 0
                              ? Colors.grey.shade700
                              : Colors.grey.shade400,
                        ),
                      ),
                    ),
                  ),

                  // Plus button (go to next set)
                  GestureDetector(
                    onTap: currentPage < 2
                        ? () {
                            setState(() {
                              _extraInningsPage++;
                              _showExtraInnings = true;
                              _selectedRbiInning =
                                  null; // Clear selection when switching
                              _isPriorToGame = false; // Clear prior selection
                            });
                            _updateCaption();
                          }
                        : null,
                    child: Container(
                      width: 36,
                      height: 33,
                      alignment: Alignment.center,
                      decoration: BoxDecoration(
                        color: currentPage < 2
                            ? Colors.grey.shade50
                            : Colors.grey.shade200,
                        borderRadius: BorderRadius.circular(3),
                        border: Border.all(color: Colors.grey.shade300),
                      ),
                      child: Text(
                        '+',
                        style: TextStyle(
                          fontSize: 14,
                          fontWeight: FontWeight.w500,
                          color: currentPage < 2
                              ? Colors.grey.shade700
                              : Colors.grey.shade400,
                        ),
                      ),
                    ),
                  ),
                ],
              ),

              // Prior to the game option (for "Looks On", "Takes the Field", "Comes Off the Field", and custom text) - placed below innings
              if (_selectedVerb == 'Looks On' ||
                  _selectedVerb == 'Takes the Field' ||
                  _selectedVerb == 'Comes Off the Field' ||
                  _showCustomTextInningSelector) ...[
                const SizedBox(height: 4),
                GestureDetector(
                  onTap: () {
                    setState(() {
                      _isPriorToGame = !_isPriorToGame;
                      if (_isPriorToGame) {
                        _selectedRbiInning = null;
                      }
                    });
                    _updateCaption();
                  },
                  child: Container(
                    width: 100,
                    height: 28,
                    alignment: Alignment.center,
                    decoration: BoxDecoration(
                      color: _isPriorToGame
                          ? Colors.grey.shade300
                          : Colors.grey.shade50,
                      borderRadius: BorderRadius.circular(3),
                      border: Border.all(
                        color: Colors.grey.shade300,
                        width: 0.5,
                      ),
                    ),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 8),
                      child: Text(
                        'Prior to Game',
                        style: TextStyle(
                          fontSize: 11,
                          fontWeight: FontWeight.w500,
                          color: _isPriorToGame
                              ? Colors.white
                              : Colors.grey.shade700,
                        ),
                      ),
                    ),
                  ),
                ),
              ],
            ],
          ),
        ),
      ],
    );
  }

