  Widget _buildBothTeamsList() {
    // Get dynamic sizing based on screen dimensions
    final sizing = _getDynamicSizing();
    final dynamicFontSize = sizing['fontSize']!;
    final dynamicVerticalPadding = sizing['verticalPadding']!;

    // Use filtered rosters (respects unified and team-specific search)
    final sortedHomeRoster = List<Player>.from(_getFilteredRoster(true))
      ..sort((a, b) {
        int comparison = 0;
        if (_homePlayerSortBy == 'lastname') {
          comparison = _getLastNameFromDisplayName(
            a.displayName,
          ).compareTo(_getLastNameFromDisplayName(b.displayName));
        } else if (_homePlayerSortBy == 'firstname') {
          comparison = _getFirstNameFromDisplayName(
            a.displayName,
          ).compareTo(_getFirstNameFromDisplayName(b.displayName));
        } else {
          // number
          final aNum = int.tryParse(a.jerseyNumber ?? '0') ?? 0;
          final bNum = int.tryParse(b.jerseyNumber ?? '0') ?? 0;
          comparison = aNum.compareTo(bNum);
        }
        return _homePlayerSortAscending ? comparison : -comparison;
      });
    final sortedAwayRoster = List<Player>.from(_getFilteredRoster(false))
      ..sort((a, b) {
        int comparison = 0;
        if (_awayPlayerSortBy == 'lastname') {
          comparison = _getLastNameFromDisplayName(
            a.displayName,
          ).compareTo(_getLastNameFromDisplayName(b.displayName));
        } else if (_awayPlayerSortBy == 'firstname') {
          comparison = _getFirstNameFromDisplayName(
            a.displayName,
          ).compareTo(_getFirstNameFromDisplayName(b.displayName));
        } else {
          // number
          final aNum = int.tryParse(a.jerseyNumber ?? '0') ?? 0;
          final bNum = int.tryParse(b.jerseyNumber ?? '0') ?? 0;
          comparison = aNum.compareTo(bNum);
        }
        return _awayPlayerSortAscending ? comparison : -comparison;
      });

    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 8),
      child: Row(
        children: [
          // Home team column
          Expanded(
            child: Column(
              children: [
                // Home team header
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 6,
                  ),
                  decoration: BoxDecoration(
                    color: Colors.grey.shade100,
                    border: Border(
                      bottom: BorderSide(color: Colors.grey.shade300, width: 1),
                    ),
                  ),
                  child: Row(
                    children: [
                      Icon(Icons.home, size: 14, color: Colors.grey.shade700),
                      const SizedBox(width: 6),
                      Expanded(
                        child: Text(
                          selectedHomeTeam ?? 'Home Team',
                          style: TextStyle(
                            fontSize: 8,
                            fontWeight: FontWeight.bold,
                            color: Colors.grey.shade700,
                          ),
                          overflow: TextOverflow.ellipsis,
                        ),
                      ),
                    ],
                  ),
                ),
                // Home team players
                Expanded(
                  child: ListView.builder(
                    shrinkWrap: true,
                    itemCount: sortedHomeRoster.length,
                    itemBuilder: (context, index) {
                      final player = sortedHomeRoster[index];
                      final isSelected = selectedHomePlayers.contains(
                        player.displayName,
                      );

                      return GestureDetector(
                        onTap: () {
                          setState(() {
                            if (isSelected) {
                              selectedHomePlayers.remove(player.displayName);
                            } else {
                              if (_firstTeamSelected == null) {
                                _firstTeamSelected = true;
                                _firstPlayerSelected =
                                    _removeJerseyNumberFromName(
                                  player.displayName,
                                );
                              }
                              selectedHomePlayers.add(player.displayName);
                              _isPlayerSearchMode = false;
                            }
                          });
                          _updateCaption();
                          _reapplyVerbKeywordsIfEnabled();
                        },
                        child: Container(
                          padding: EdgeInsets.symmetric(
                            horizontal: 8,
                            vertical: dynamicVerticalPadding *
                                1.5, // Slightly more padding for this view
                          ),
                          decoration: BoxDecoration(
                            color: isSelected
                                ? Colors.blue.shade600
                                : Colors.white,
                            border: Border(
                              bottom: BorderSide(
                                color: isSelected
                                    ? Colors.blue.shade600
                                    : Colors.grey.shade200,
                                width: 0.5,
                              ),
                            ),
                          ),
                          child: Row(
                            children: [
                              if (isSelected &&
                                  _isFirstSelectedPlayer(player.displayName))
                                Container(
                                  margin: const EdgeInsets.only(right: 6),
                                  padding: const EdgeInsets.all(1),
                                  decoration: BoxDecoration(
                                    color: Colors.orange,
                                    borderRadius: BorderRadius.circular(2),
                                  ),
                                  child: const Icon(
                                    Icons.star,
                                    size: 8,
                                    color: Colors.white,
                                  ),
                                ),
                              Text(
                                '🔥H${player.jerseyNumber ?? "?"}',
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: FontWeight.bold,
                                  color: isSelected
                                      ? Colors.white
                                      : Colors.grey.shade600,
                                ),
                              ),
                              const SizedBox(width: 8),
                              Expanded(
                                child: Text(
                                  _removeJerseyNumberFromName(
                                    player.displayName,
                                  ),
                                  style: TextStyle(
                                    fontSize: dynamicFontSize,
                                    fontWeight: isSelected
                                        ? FontWeight.w600
                                        : FontWeight.normal,
                                    color: isSelected
                                        ? Colors.white
                                        : Colors.black87,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                ),
                              ),
                            ],
                          ),
                        ),
                      );
                    },
                  ),
                ),
              ],
            ),
          ),
          // Divider between teams
          Container(
            width: 1,
            color: Colors.grey.shade300,
            margin: const EdgeInsets.symmetric(horizontal: 4),
          ),
          // Away team column
          Expanded(
            child: Column(
              children: [
                // Away team header
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 6,
                  ),
                  decoration: BoxDecoration(
                    color: Colors.grey.shade100,
                    border: Border(
                      bottom: BorderSide(color: Colors.grey.shade300, width: 1),
                    ),
                  ),
                  child: Row(
                    children: [
                      Icon(Icons.flight, size: 14, color: Colors.grey.shade700),
                      const SizedBox(width: 6),
                      Expanded(
                        child: Text(
                          selectedAwayTeam ?? 'Away Team',
                          style: TextStyle(
                            fontSize: 8,
                            fontWeight: FontWeight.bold,
                            color: Colors.grey.shade700,
                          ),
                          overflow: TextOverflow.ellipsis,
                        ),
                      ),
                    ],
                  ),
                ),
                // Away team players
                Expanded(
                  child: ListView.builder(
                    shrinkWrap: true,
                    itemCount: sortedAwayRoster.length,
                    itemBuilder: (context, index) {
                      final player = sortedAwayRoster[index];
                      final isSelected = selectedAwayPlayers.contains(
                        player.displayName,
                      );

                      return GestureDetector(
                        onTap: () {
                          setState(() {
                            if (isSelected) {
                              selectedAwayPlayers.remove(player.displayName);
                            } else {
                              if (_firstTeamSelected == null) {
                                _firstTeamSelected = false;
                                _firstPlayerSelected =
                                    _removeJerseyNumberFromName(
                                  player.displayName,
                                );
                              }
                              selectedAwayPlayers.add(player.displayName);
                              _isPlayerSearchMode = false;
                            }
                          });
                          _updateCaption();
                          _reapplyVerbKeywordsIfEnabled();
                        },
                        child: Container(
                          padding: EdgeInsets.symmetric(
                            horizontal: 8,
                            vertical: dynamicVerticalPadding *
                                1.5, // Slightly more padding for this view
                          ),
                          decoration: BoxDecoration(
                            color: isSelected
                                ? Colors.blue.shade600
                                : Colors.grey.shade50,
                            border: Border(
                              bottom: BorderSide(
                                color: isSelected
                                    ? Colors.blue.shade600
                                    : Colors.grey.shade200,
                                width: 0.5,
                              ),
                            ),
                          ),
                          child: Row(
                            children: [
                              if (isSelected &&
                                  _isFirstSelectedPlayer(player.displayName))
                                Container(
                                  margin: const EdgeInsets.only(right: 6),
                                  padding: const EdgeInsets.all(1),
                                  decoration: BoxDecoration(
                                    color: Colors.orange,
                                    borderRadius: BorderRadius.circular(2),
                                  ),
                                  child: const Icon(
                                    Icons.star,
                                    size: 8,
                                    color: Colors.white,
                                  ),
                                ),
                              Text(
                                '🔥V${player.jerseyNumber ?? "?"}',
                                style: TextStyle(
                                  fontSize: 11,
                                  fontWeight: FontWeight.bold,
                                  color: isSelected
                                      ? Colors.white
                                      : Colors.grey.shade600,
                                ),
                              ),
                              const SizedBox(width: 8),
                              Expanded(
                                child: Text(
                                  _removeJerseyNumberFromName(
                                    player.displayName,
                                  ),
                                  style: TextStyle(
                                    fontSize: dynamicFontSize,
                                    fontWeight: isSelected
                                        ? FontWeight.w600
                                        : FontWeight.normal,
                                    color: isSelected
                                        ? Colors.white
                                        : Colors.black87,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                ),
                              ),
                            ],
                          ),
                        ),
                      );
                    },
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

// ── Byline Editor Dialog ─────────────────────────────────────────────────────

class _BylineEditorDialog extends StatefulWidget {
  final String initialPhotographer;
  final String initialCredit;
  final String initialPrefixText;
  final bool initialUseBrackets;
  final bool initialUseSlash;
  /// Raw metadata values (before any override). Used to show variable indicators.
  final String metadataPhotographer;
  final String metadataCredit;
  final void Function(
      String photographer,
      String credit,
      String prefixText,
      bool useBrackets,
      bool useSlash) onApply;
  final VoidCallback onClear;

  const _BylineEditorDialog({
    required this.initialPhotographer,
    required this.initialCredit,
    required this.initialPrefixText,
    required this.initialUseBrackets,
    required this.initialUseSlash,
    required this.metadataPhotographer,
    required this.metadataCredit,
    required this.onApply,
    required this.onClear,
  });

  @override
  State<_BylineEditorDialog> createState() => _BylineEditorDialogState();
}

class _BylineEditorDialogState extends State<_BylineEditorDialog> {
  late final TextEditingController _photographerCtrl;
  late final TextEditingController _creditCtrl;
  late final TextEditingController _prefixCtrl;
  final FocusNode _photographerFocus = FocusNode();
  final FocusNode _creditFocus = FocusNode();
  late bool _useBrackets;
  late bool _useSlash;

  @override
  void initState() {
    super.initState();
    _photographerCtrl =
        TextEditingController(text: widget.initialPhotographer);
    _creditCtrl = TextEditingController(text: widget.initialCredit);
    _prefixCtrl = TextEditingController(text: widget.initialPrefixText);
    _useBrackets = widget.initialUseBrackets;
    _useSlash = widget.initialUseSlash;
    _photographerCtrl.addListener(() => setState(() {}));
    _creditCtrl.addListener(() => setState(() {}));
    _prefixCtrl.addListener(() => setState(() {}));
  }

  @override
  void dispose() {
    _photographerCtrl.dispose();
    _creditCtrl.dispose();
    _prefixCtrl.dispose();
    _photographerFocus.dispose();
    _creditFocus.dispose();
    super.dispose();
  }

  String get _previewByline {
    final p = _photographerCtrl.text.trim();
    final c = _creditCtrl.text.trim();
    String inner = '';
    if (p.isNotEmpty && c.isNotEmpty) {
      inner = _useSlash ? '$p/$c' : '$p $c';
    } else if (p.isNotEmpty) {
      inner = p;
    } else if (c.isNotEmpty) {
      inner = c;
    }
    if (inner.isEmpty) return '';
    final prefix = _prefixCtrl.text.trim();
    final body = prefix.isNotEmpty ? '$prefix $inner' : inner;
    return _useBrackets ? '($body)' : body;
  }

  bool get _photographerIsOverridden =>
      _photographerCtrl.text.trim() != widget.metadataPhotographer.trim();
  bool get _creditIsOverridden =>
      _creditCtrl.text.trim() != widget.metadataCredit.trim();

  @override
  Widget build(BuildContext context) {
    final preview = _previewByline;

    return Dialog(
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(4)),
      backgroundColor: Colors.grey.shade50,
      child: Container(
        width: 380,
        decoration: BoxDecoration(
          color: Colors.grey.shade50,
          borderRadius: BorderRadius.circular(4),
          border: Border.all(color: Colors.grey.shade300),
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Header bar — matches _buildKbLabeledBox style
            Container(
              padding: const EdgeInsets.fromLTRB(8, 4, 6, 4),
              decoration: BoxDecoration(
                color: Colors.grey.shade50,
                borderRadius: const BorderRadius.only(
                  topLeft: Radius.circular(4),
                  topRight: Radius.circular(4),
                ),
                border: Border(
                  bottom: BorderSide(color: Colors.grey.shade300, width: 1),
                ),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.07),
                    blurRadius: 2,
                    offset: const Offset(0, 1),
                  ),
                ],
              ),
              child: Row(
                children: [
                  const Icon(Icons.edit_outlined,
                      size: 11, color: Colors.black54),
                  const SizedBox(width: 4),
                  Text(
                    'Edit Byline',
                    style: TextStyle(
                      fontSize: 10,
                      fontWeight: FontWeight.w500,
                      color: Colors.grey.shade700,
                    ),
                  ),
                  const Spacer(),
                  GestureDetector(
                    onTap: () => Navigator.of(context).pop(),
                    child: Icon(Icons.close,
                        size: 13, color: Colors.grey.shade500),
                  ),
                ],
              ),
            ),

            // Content
            Padding(
              padding: const EdgeInsets.fromLTRB(10, 8, 10, 10),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // Photographer field
                  _fieldLabel(
                    'Photographer',
                    varSource: 'IPTC: Creator / By-line',
                    isOverridden: _photographerIsOverridden,
                    metadataValue: widget.metadataPhotographer,
                    ctrl: _photographerCtrl,
                    focusNode: _photographerFocus,
                  ),
                  const SizedBox(height: 3),
                  _field(_photographerCtrl,
                      hint: 'e.g. Mark Blinch',
                      isOverridden: _photographerIsOverridden,
                      focusNode: _photographerFocus),

                  const SizedBox(height: 8),

                  // Credit / Agency field
                  _fieldLabel(
                    'Credit / Agency',
                    varSource: 'IPTC: Credit',
                    isOverridden: _creditIsOverridden,
                    metadataValue: widget.metadataCredit,
                    ctrl: _creditCtrl,
                    focusNode: _creditFocus,
                  ),
                  const SizedBox(height: 3),
                  _field(_creditCtrl,
                      hint: 'e.g. NHLI via Getty Images',
                      isOverridden: _creditIsOverridden,
                      focusNode: _creditFocus),

                  const SizedBox(height: 8),

                  // Format options
                  Container(
                    padding: const EdgeInsets.symmetric(
                        horizontal: 8, vertical: 6),
                    decoration: BoxDecoration(
                      color: const Color(0xFFFCFCFC),
                      border: Border.all(color: Colors.grey.shade300),
                    ),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          'FORMAT',
                          style: TextStyle(
                            fontSize: 8,
                            fontWeight: FontWeight.w600,
                            color: Colors.grey.shade500,
                            letterSpacing: 0.6,
                          ),
                        ),
                        const SizedBox(height: 6),
                        // Prefix text row
                        Row(
                          children: [
                            Text(
                              'Prefix text',
                              style: TextStyle(
                                fontSize: 10,
                                color: Colors.grey.shade700,
                              ),
                            ),
                            const SizedBox(width: 8),
                            Expanded(
                              child: TextField(
                                controller: _prefixCtrl,
                                style: const TextStyle(fontSize: 10),
                                decoration: InputDecoration(
                                  hintText: 'e.g. Photo by',
                                  hintStyle: TextStyle(
                                      color: Colors.grey.shade400,
                                      fontSize: 10),
                                  isDense: true,
                                  contentPadding:
                                      const EdgeInsets.symmetric(
                                          horizontal: 6, vertical: 4),
                                  border: OutlineInputBorder(
                                      borderRadius:
                                          BorderRadius.circular(3)),
                                  enabledBorder: OutlineInputBorder(
                                    borderRadius: BorderRadius.circular(3),
                                    borderSide: BorderSide(
                                        color: Colors.grey.shade400),
                                  ),
                                  focusedBorder: OutlineInputBorder(
                                    borderRadius: BorderRadius.circular(3),
                                    borderSide: const BorderSide(
                                        color: Color(0xFF1976D2), width: 1.5),
                                  ),
                                  filled: true,
                                  fillColor: Colors.white,
                                ),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 6),
                        // Brackets + Slash toggles
                        Row(
                          children: [
                            _optionCheckbox(
                              label: 'Brackets',
                              value: _useBrackets,
                              onTap: () => setState(
                                  () => _useBrackets = !_useBrackets),
                            ),
                            const SizedBox(width: 16),
                            _optionCheckbox(
                              label: 'Slash separator',
                              value: _useSlash,
                              onTap: () =>
                                  setState(() => _useSlash = !_useSlash),
                            ),
                          ],
                        ),
                      ],
                    ),
                  ),

                  const SizedBox(height: 8),

                  // Live preview
                  Container(
                    width: double.infinity,
                    padding: const EdgeInsets.symmetric(
                        horizontal: 8, vertical: 6),
                    decoration: BoxDecoration(
                      color: const Color(0xFFFCFCFC),
                      border: Border.all(color: Colors.grey.shade300),
                    ),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          'PREVIEW',
                          style: TextStyle(
                            fontSize: 8,
                            fontWeight: FontWeight.w600,
                            color: Colors.grey.shade500,
                            letterSpacing: 0.6,
                          ),
                        ),
                        const SizedBox(height: 3),
                        Text(
                          preview.isNotEmpty ? preview : '(no byline)',
                          style: TextStyle(
                            fontSize: 10,
                            color: preview.isNotEmpty
                                ? Colors.black87
                                : Colors.grey.shade400,
                            fontStyle: preview.isEmpty
                                ? FontStyle.italic
                                : FontStyle.normal,
                          ),
                        ),
                      ],
                    ),
                  ),

                  const SizedBox(height: 10),

                  // Buttons
                  Row(
                    children: [
                      GestureDetector(
                        onTap: () {
                          widget.onClear();
                          Navigator.of(context).pop();
                        },
                        child: Text(
                          'Reset to Metadata',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.red.shade500,
                          ),
                        ),
                      ),
                      const Spacer(),
                      GestureDetector(
                        onTap: () => Navigator.of(context).pop(),
                        child: Text(
                          'Cancel',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.grey.shade600,
                          ),
                        ),
                      ),
                      const SizedBox(width: 12),
                      GestureDetector(
                        onTap: () {
                          widget.onApply(
                            _photographerCtrl.text,
                            _creditCtrl.text,
                            _prefixCtrl.text.trim(),
                            _useBrackets,
                            _useSlash,
                          );
                          Navigator.of(context).pop();
                        },
                        child: Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 10, vertical: 4),
                          decoration: BoxDecoration(
                            color: const Color(0xFF1976D2),
                            borderRadius: BorderRadius.circular(3),
                          ),
                          child: const Text(
                            'Apply',
                            style: TextStyle(
                              fontSize: 10,
                              color: Colors.white,
                              fontWeight: FontWeight.w500,
                            ),
                          ),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  /// Compact checkbox row used for format options.
  Widget _optionCheckbox({
    required String label,
    required bool value,
    required VoidCallback onTap,
  }) {
    return GestureDetector(
      onTap: onTap,
      child: Row(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          Container(
            width: 12,
            height: 12,
            decoration: BoxDecoration(
              border: Border.all(
                color: value
                    ? const Color(0xFF1976D2)
                    : Colors.grey.shade400,
                width: 1.2,
              ),
              borderRadius: BorderRadius.circular(2),
              color: value ? const Color(0xFF1976D2) : Colors.white,
            ),
            child: value
                ? const Center(
                    child: Icon(Icons.check, size: 9, color: Colors.white),
                  )
                : null,
          ),
          const SizedBox(width: 4),
          Text(
            label,
            style: TextStyle(
              fontSize: 10,
              color: value ? Colors.black87 : Colors.grey.shade500,
            ),
          ),
        ],
      ),
    );
  }

  /// Label row: field name + variable source chip + "Use metadata" checkbox.
  Widget _fieldLabel(
    String text, {
    required String varSource,
    required bool isOverridden,
    required String metadataValue,
    required TextEditingController ctrl,
    FocusNode? focusNode,
  }) {
    final usingMetadata = !isOverridden && metadataValue.isNotEmpty;
    return Row(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        Text(
          text,
          style: TextStyle(
            fontSize: 10,
            fontWeight: FontWeight.w500,
            color: Colors.grey.shade700,
          ),
        ),
        const SizedBox(width: 6),
        // Variable source chip
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
          decoration: BoxDecoration(
            color: const Color(0xFFE8F0FE),
            borderRadius: BorderRadius.circular(4),
            border: Border.all(color: const Color(0xFFBBCEFA)),
          ),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              const Icon(Icons.data_object, size: 9, color: Color(0xFF1565C0)),
              const SizedBox(width: 3),
              Text(
                varSource,
                style: const TextStyle(
                  fontSize: 9,
                  color: Color(0xFF1565C0),
                  fontWeight: FontWeight.w500,
                ),
              ),
            ],
          ),
        ),
        if (metadataValue.isNotEmpty) ...[
          const SizedBox(width: 8),
          // "Use metadata" checkbox
          GestureDetector(
            onTap: () {
              final wasUsingMetadata = usingMetadata;
              setState(() {
                if (wasUsingMetadata) {
                  ctrl.text = '';
                } else {
                  ctrl.text = metadataValue;
                }
              });
              if (wasUsingMetadata) {
                WidgetsBinding.instance.addPostFrameCallback((_) {
                  focusNode?.requestFocus();
                });
              }
            },
            child: Row(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.center,
              children: [
                Container(
                  width: 12,
                  height: 12,
                  decoration: BoxDecoration(
                    border: Border.all(
                      color: usingMetadata
                          ? const Color(0xFF1976D2)
                          : Colors.grey.shade400,
                      width: 1.2,
                    ),
                    borderRadius: BorderRadius.circular(2),
                    color: usingMetadata
                        ? const Color(0xFF1976D2)
                        : Colors.white,
                  ),
                  child: usingMetadata
                      ? const Center(
                          child: Icon(Icons.check,
                              size: 9, color: Colors.white),
                        )
                      : null,
                ),
                const SizedBox(width: 4),
                Text(
                  'Use metadata',
                  style: TextStyle(
                    fontSize: 10,
                    color: usingMetadata
                        ? Colors.black87
                        : Colors.grey.shade500,
                    fontWeight: FontWeight.w400,
                  ),
                ),
              ],
            ),
          ),
        ],
      ],
    );
  }

  Widget _field(TextEditingController ctrl,
      {String hint = '', bool isOverridden = false, FocusNode? focusNode}) {
    final borderColor =
        isOverridden ? const Color(0xFFFFB74D) : Colors.grey.shade400;
    final fillColor =
        isOverridden ? const Color(0xFFFFFBF5) : Colors.white;
    return TextField(
      controller: ctrl,
      focusNode: focusNode,
      style: const TextStyle(fontSize: 11),
      decoration: InputDecoration(
        hintText: hint,
        hintStyle: TextStyle(color: Colors.grey.shade400, fontSize: 11),
        isDense: true,
        border: OutlineInputBorder(borderRadius: BorderRadius.circular(6)),
        enabledBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(6),
          borderSide: BorderSide(color: borderColor),
        ),
        focusedBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(6),
          borderSide: BorderSide(
            color: isOverridden
                ? const Color(0xFFE65100)
                : const Color(0xFF1976D2),
            width: 2,
          ),
        ),
        contentPadding:
            const EdgeInsets.symmetric(horizontal: 7, vertical: 5),
        filled: true,
        fillColor: fillColor,
      ),
    );
  }
}
